module.exports = { corpus: "\n\n--- WEEK 1 CONTENT ---\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Week 1: Foundations & Ecosystem Mapping | FairPay CEO Course</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--bg:#ffffff;--card:#f8fafc;--elevated:#f1f5f9;--teal:#0d9488;--teal-dim:rgba(13,148,136,.1);--orange:#ea580c;--text:#0f172a;--text2:#475569;--muted:#64748b;--border:#e2e8f0;--success:#16a34a}\n*{margin:0;padding:0;box-sizing:border-box}\nbody{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);line-height:1.7}\n.nav{position:sticky;top:0;background:rgba(255,255,255,.95);backdrop-filter:blur(10px);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;justify-content:space-between;z-index:100}\n.nav a{color:var(--text2);text-decoration:none;font-size:.9rem}.nav a:hover{color:var(--teal)}\n.hero{padding:4rem 2rem 3rem;background:linear-gradient(180deg,rgba(13,148,136,.06),transparent);border-bottom:1px solid var(--border);text-align:center}\n.week-label{display:inline-block;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--teal);background:var(--teal-dim);padding:.5rem 1rem;border-radius:2rem;margin-bottom:1rem}\nh1{font-family:'Instrument Serif',serif;font-size:clamp(2rem,5vw,3rem);font-weight:400;margin-bottom:1rem}\n.subtitle{color:var(--text2);max-width:700px;margin:0 auto;font-size:1.1rem}\n.progress-bar{max-width:600px;margin:2rem auto 0;display:flex;gap:.5rem}\n.progress-step{flex:1;height:4px;background:var(--border);border-radius:2px}.progress-step.active{background:var(--teal)}\n.container{max-width:800px;margin:0 auto;padding:2rem}\n.section{margin-bottom:4rem}\nh2{font-family:'Instrument Serif',serif;font-size:1.75rem;margin-bottom:1.5rem;color:var(--text);border-bottom:2px solid var(--teal);padding-bottom:.5rem;display:inline-block}\nh3{font-size:1.2rem;margin:2rem 0 1rem;color:var(--text);font-weight:600}\nh4{font-size:1rem;margin:1.5rem 0 .75rem;color:var(--teal);font-weight:600}\np{margin-bottom:1rem;color:var(--text2)}\n.card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1.5rem}\n.intro-card{background:linear-gradient(135deg,var(--teal-dim),transparent);border:1px solid rgba(13,148,136,.2);padding:2rem}\n.concept{background:var(--bg);border-left:4px solid var(--teal);padding:1.25rem;margin-bottom:1.5rem;border-radius:0 8px 8px 0;box-shadow:0 1px 3px rgba(0,0,0,.05)}\n.concept-title{font-weight:600;color:var(--teal);font-size:1.1rem;margin-bottom:.5rem}\n.concept p{margin-bottom:.5rem}.concept p:last-child{margin-bottom:0}\n.diagram-container{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin:2rem 0;text-align:center}\n.diagram-title{font-size:.8rem;font-weight:600;color:var(--muted);text-transform:uppercase;letter-spacing:.05em;margin-bottom:1rem}\n.diagram-caption{font-size:.9rem;color:var(--text2);margin-top:1rem;font-style:italic}\n.diagram-container svg{max-width:100%;height:auto}\n.example-box{background:var(--elevated);border:1px solid var(--border);border-radius:8px;padding:1.25rem;margin:1rem 0}\n.example-label{font-size:.75rem;font-weight:600;color:var(--orange);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.5rem}\n.comparison-table{width:100%;border-collapse:collapse;margin:1.5rem 0;font-size:.9rem}\n.comparison-table th,.comparison-table td{padding:1rem;text-align:left;border:1px solid var(--border)}\n.comparison-table th{background:var(--elevated);color:var(--teal);font-weight:600}\n.comparison-table td{color:var(--text2)}\n.key-point{background:var(--teal-dim);border:1px solid rgba(13,148,136,.2);border-radius:8px;padding:1.25rem;margin:1.5rem 0}\n.key-point-title{font-weight:600;color:var(--teal);margin-bottom:.5rem}\n.institution{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1rem}\n.institution-header{display:flex;justify-content:space-between;align-items:start;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem}\n.institution-name{font-weight:600;font-size:1.1rem;color:var(--text)}\n.institution-type{font-size:.75rem;background:var(--elevated);color:var(--muted);padding:.25rem .75rem;border-radius:1rem}\n.institution-role{color:var(--text2);font-size:.95rem;margin-bottom:.75rem}\n.institution-relevance{background:var(--teal-dim);padding:.75rem;border-radius:6px;font-size:.9rem;color:var(--text)}\n.resource{display:flex;gap:1rem;padding:1.25rem;background:var(--card);border:1px solid var(--border);border-radius:8px;margin-bottom:.75rem;text-decoration:none;color:inherit;transition:all .2s}\n.resource:hover{border-color:var(--teal);box-shadow:0 2px 8px rgba(13,148,136,.1)}\n.resource-num{width:32px;height:32px;background:var(--teal);color:white;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:.85rem;font-weight:600;flex-shrink:0}\n.resource-content{flex:1}\n.resource-title{font-weight:600;color:var(--text);margin-bottom:.25rem}\n.resource-desc{font-size:.85rem;color:var(--muted)}\n.resource-time{font-size:.75rem;color:var(--teal);margin-top:.25rem}\n.quiz-container{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:2rem}\n.quiz-intro{margin-bottom:2rem;padding-bottom:1.5rem;border-bottom:1px solid var(--border)}\n.q{margin-bottom:2rem;padding-bottom:2rem;border-bottom:1px solid var(--border)}.q:last-of-type{border:none;margin-bottom:1rem}\n.q-num{font-size:.75rem;font-weight:600;color:var(--teal);text-transform:uppercase;margin-bottom:.5rem}\n.q-text{font-weight:500;font-size:1.05rem;margin-bottom:1rem;color:var(--text)}\n.opts label{display:block;padding:.875rem 1rem;margin:.5rem 0;background:var(--bg);border:1px solid var(--border);border-radius:8px;cursor:pointer;transition:all .2s;color:var(--text2)}\n.opts label:hover{border-color:var(--teal);background:var(--teal-dim)}\n.opts input{margin-right:.75rem}\n.feedback{margin-top:.75rem;padding:1rem;border-radius:8px;font-size:.9rem;display:none}\n.feedback.correct{display:block;background:rgba(22,163,74,.1);border:1px solid rgba(22,163,74,.2);color:var(--success)}\n.feedback.incorrect{display:block;background:rgba(234,88,12,.1);border:1px solid rgba(234,88,12,.2);color:var(--orange)}\n.btn{background:var(--teal);color:#fff;border:none;padding:.875rem 2rem;border-radius:8px;cursor:pointer;font-weight:600;font-size:1rem}\n.btn:hover{background:#0f766e}\n.score-display{margin-top:2rem;padding:2rem;background:var(--elevated);border-radius:12px;text-align:center;display:none}\n.score-display.visible{display:block}\n.score-num{font-family:'Instrument Serif',serif;font-size:3.5rem;color:var(--teal)}\n.score-label{color:var(--muted);margin-bottom:1rem}\n.deliverable{background:linear-gradient(135deg,var(--teal-dim),transparent);border:2px solid var(--teal);border-radius:16px;padding:2rem}\n.deliverable h3{font-family:'Instrument Serif',serif;font-size:1.5rem;margin:0 0 1rem;color:var(--teal)}\n.checklist{list-style:none;padding:0}\n.checklist li{padding:1rem;margin-bottom:.75rem;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text2)}\n.checklist li strong{color:var(--text);display:block;margin-bottom:.25rem}\n.nav-footer{display:flex;justify-content:space-between;margin-top:4rem;padding-top:2rem;border-top:1px solid var(--border)}\n.nav-btn{padding:1rem 1.5rem;background:var(--card);border:1px solid var(--border);border-radius:8px;text-decoration:none;color:var(--text2);font-weight:500}\n.nav-btn:hover{border-color:var(--teal);color:var(--teal)}\n.nav-btn.primary{background:var(--teal);color:white;border-color:var(--teal)}\n.nav-btn.primary:hover{background:#0f766e}\n</style>\n</head>\n<body>\n<nav class=\"nav\">\n<a href=\"../index.html\">← Course Home</a>\n<span style=\"color:var(--text);font-weight:600\">Week 1 of 6</span>\n<a href=\"week2.html\">Week 2 →</a>\n</nav>\n\n<header class=\"hero\">\n<span class=\"week-label\">Week 1</span>\n<h1>Foundations & Ecosystem Mapping</h1>\n<p class=\"subtitle\">Build the mental model that every payments decision depends on. Map where FairPay fits in Australia's ecosystem.</p>\n<div class=\"progress-bar\">\n<div class=\"progress-step active\"></div>\n<div class=\"progress-step\"></div>\n<div class=\"progress-step\"></div>\n<div class=\"progress-step\"></div>\n<div class=\"progress-step\"></div>\n<div class=\"progress-step\"></div>\n</div>\n</header>\n\n<div class=\"container\">\n\n<!-- INTRODUCTION -->\n<section class=\"section\">\n<div class=\"card intro-card\">\n<h3 style=\"margin-top:0;color:var(--teal)\">Why This Week Matters</h3>\n<p>Before you make any payments decision—which rails to use, who to partner with, how to price—you need three concepts locked in. CEOs who don't have this mental model make expensive mistakes: they misprice risk, pick wrong partners, and build wrong products.</p>\n<p style=\"margin-bottom:0\">This week gives you the foundational vocabulary and framework. Everything in Weeks 2-6 builds on these concepts.</p>\n</div>\n\n<h2>Learning Objectives</h2>\n<div class=\"card\">\n<p style=\"margin-bottom:1rem\">By the end of this week, you will be able to:</p>\n<ul style=\"color:var(--text2);padding-left:1.5rem;margin:0\">\n<li style=\"margin-bottom:.5rem\">Explain the difference between clearing and settlement</li>\n<li style=\"margin-bottom:.5rem\">Define finality and articulate its implications for risk</li>\n<li style=\"margin-bottom:.5rem\">Distinguish push vs pull payments and position PayTo</li>\n<li style=\"margin-bottom:.5rem\">Map Australia's payments ecosystem and key institutions</li>\n<li>Identify FairPay's positioning options and control points</li>\n</ul>\n</div>\n</section>\n\n<!-- CLEARING VS SETTLEMENT -->\n<section class=\"section\">\n<h2>Core Payment Primitives</h2>\n\n<div class=\"concept\">\n<div class=\"concept-title\">1. Clearing vs Settlement</div>\n<p><strong>Clearing</strong> is the process of exchanging payment instructions and calculating obligations. Think of it as the messaging layer—authorization requests, confirmations, instructions. This is <em>information</em>, not money.</p>\n<p><strong>Settlement</strong> is when actual money moves. In Australia, final settlement happens in \"central bank money\" at the RBA via <strong>Exchange Settlement Accounts (ESAs)</strong>.</p>\n</div>\n\n<!-- CLEARING VS SETTLEMENT DIAGRAM -->\n<div class=\"diagram-container\">\n<div class=\"diagram-title\">Clearing vs Settlement Flow</div>\n<svg viewBox=\"0 0 700 320\" xmlns=\"http://www.w3.org/2000/svg\">\n  <!-- Background sections -->\n  <rect x=\"20\" y=\"60\" width=\"310\" height=\"240\" rx=\"12\" fill=\"#f0fdfa\" stroke=\"#99f6e4\" stroke-width=\"2\"/>\n  <rect x=\"370\" y=\"60\" width=\"310\" height=\"240\" rx=\"12\" fill=\"#fef3c7\" stroke=\"#fcd34d\" stroke-width=\"2\"/>\n  \n  <!-- Section Labels -->\n  <text x=\"175\" y=\"40\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#0d9488\">CLEARING</text>\n  <text x=\"175\" y=\"55\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" fill=\"#64748b\">Information Exchange</text>\n  <text x=\"525\" y=\"40\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#d97706\">SETTLEMENT</text>\n  <text x=\"525\" y=\"55\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" fill=\"#64748b\">Money Movement</text>\n  \n  <!-- Clearing side icons -->\n  <rect x=\"60\" y=\"90\" width=\"100\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n  <text x=\"110\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"#0f172a\">Customer</text>\n  <text x=\"110\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Initiates</text>\n  <text x=\"110\" y=\"143\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">payment</text>\n  \n  <rect x=\"190\" y=\"90\" width=\"100\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n  <text x=\"240\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"#0f172a\">Payment</text>\n  <text x=\"240\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"#0f172a\">Network</text>\n  <text x=\"240\" y=\"143\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Routes message</text>\n  \n  <!-- Arrows for clearing -->\n  <path d=\"M160 120 L185 120\" stroke=\"#0d9488\" stroke-width=\"2\" fill=\"none\" marker-end=\"url(#arrowTeal)\"/>\n  \n  <!-- Message bubbles -->\n  <rect x=\"50\" y=\"170\" width=\"120\" height=\"50\" rx=\"6\" fill=\"#ccfbf1\" stroke=\"#5eead4\"/>\n  <text x=\"110\" y=\"192\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">\"Pay $100 to</text>\n  <text x=\"110\" y=\"205\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">Merchant ABC\"</text>\n  \n  <rect x=\"180\" y=\"170\" width=\"120\" height=\"50\" rx=\"6\" fill=\"#ccfbf1\" stroke=\"#5eead4\"/>\n  <text x=\"240\" y=\"192\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">\"Authorized ✓\"</text>\n  <text x=\"240\" y=\"205\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">\"Proceed\"</text>\n  \n  <!-- Messages label -->\n  <text x=\"175\" y=\"250\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" fill=\"#0d9488\">📨 Messages only</text>\n  <text x=\"175\" y=\"268\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" fill=\"#64748b\">No money has moved yet</text>\n  \n  <!-- Settlement side -->\n  <rect x=\"410\" y=\"90\" width=\"100\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#d97706\" stroke-width=\"2\"/>\n  <text x=\"460\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"#0f172a\">Bank A</text>\n  <text x=\"460\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">ESA Balance:</text>\n  <text x=\"460\" y=\"143\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">-$100</text>\n  \n  <rect x=\"540\" y=\"90\" width=\"100\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#d97706\" stroke-width=\"2\"/>\n  <text x=\"590\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"#0f172a\">Bank B</text>\n  <text x=\"590\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">ESA Balance:</text>\n  <text x=\"590\" y=\"143\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">+$100</text>\n  \n  <!-- RBA box -->\n  <rect x=\"440\" y=\"170\" width=\"170\" height=\"60\" rx=\"8\" fill=\"#fef3c7\" stroke=\"#f59e0b\" stroke-width=\"2\"/>\n  <text x=\"525\" y=\"195\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#0f172a\">🏛️ RBA</text>\n  <text x=\"525\" y=\"212\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Fast Settlement Service</text>\n  \n  <!-- Money arrow -->\n  <path d=\"M460 155 L460 165 L590 165 L590 155\" stroke=\"#16a34a\" stroke-width=\"3\" fill=\"none\"/>\n  <circle cx=\"525\" cy=\"165\" r=\"12\" fill=\"#16a34a\"/>\n  <text x=\"525\" y=\"169\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"white\">$</text>\n  \n  <!-- Settlement label -->\n  <text x=\"525\" y=\"260\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" fill=\"#d97706\">💰 Actual funds move</text>\n  <text x=\"525\" y=\"278\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" fill=\"#64748b\">Final & irrevocable</text>\n  \n  <!-- Arrow marker definitions -->\n  <defs>\n    <marker id=\"arrowTeal\" markerWidth=\"10\" markerHeight=\"10\" refX=\"9\" refY=\"3\" orient=\"auto\" markerUnits=\"strokeWidth\">\n      <path d=\"M0,0 L0,6 L9,3 z\" fill=\"#0d9488\"/>\n    </marker>\n  </defs>\n</svg>\n<div class=\"diagram-caption\">Clearing exchanges information; Settlement moves actual money through RBA accounts</div>\n</div>\n\n<div class=\"example-box\">\n<div class=\"example-label\">Why This Matters for FairPay</div>\n<p style=\"margin-bottom:0\">When you tell a merchant \"the money's coming,\" what are you promising? With NPP/PayTo, clearing AND settlement happen in near real-time—that's powerful. With cards, clearing is instant but settlement comes later in batches, and chargebacks can reverse it months later.</p>\n</div>\n\n<!-- FINALITY -->\n<div class=\"concept\">\n<div class=\"concept-title\">2. Finality</div>\n<p>When is a payment truly done? When can neither party reverse it?</p>\n<p>With PayTo, once settlement occurs through the Fast Settlement Service—<strong>it's final</strong>. The payer can't call their bank and reverse it like a card chargeback. That's a feature for collections: more certainty, less fraud risk.</p>\n</div>\n\n<!-- FINALITY COMPARISON DIAGRAM -->\n<div class=\"diagram-container\">\n<div class=\"diagram-title\">Finality Comparison Across Rails</div>\n<svg viewBox=\"0 0 700 280\" xmlns=\"http://www.w3.org/2000/svg\">\n  <!-- Timeline base -->\n  <line x1=\"50\" y1=\"140\" x2=\"650\" y2=\"140\" stroke=\"#e2e8f0\" stroke-width=\"3\"/>\n  \n  <!-- Time markers -->\n  <text x=\"50\" y=\"170\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Payment</text>\n  <text x=\"50\" y=\"182\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Initiated</text>\n  <text x=\"200\" y=\"170\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Minutes</text>\n  <text x=\"350\" y=\"170\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Days</text>\n  <text x=\"500\" y=\"170\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Weeks</text>\n  <text x=\"650\" y=\"170\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Months</text>\n  \n  <!-- PayTo bar (strongest) -->\n  <rect x=\"50\" y=\"40\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#0d9488\"/>\n  <text x=\"100\" y=\"60\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"white\">PayTo</text>\n  <circle cx=\"150\" cy=\"55\" r=\"12\" fill=\"#16a34a\"/>\n  <text x=\"150\" y=\"59\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"white\">✓</text>\n  <text x=\"175\" y=\"50\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\" font-weight=\"600\">FINAL</text>\n  <text x=\"175\" y=\"63\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#64748b\">in seconds</text>\n  \n  <!-- BECS bar (moderate) -->\n  <rect x=\"50\" y=\"80\" width=\"300\" height=\"30\" rx=\"4\" fill=\"#f59e0b\"/>\n  <text x=\"100\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"white\">BECS</text>\n  <circle cx=\"350\" cy=\"95\" r=\"12\" fill=\"#d97706\"/>\n  <text x=\"350\" y=\"99\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"white\">~</text>\n  <text x=\"380\" y=\"90\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#d97706\" font-weight=\"600\">Indemnity window</text>\n  <text x=\"380\" y=\"103\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#64748b\">Claims possible</text>\n  \n  <!-- Cards bar (weakest) -->\n  <rect x=\"50\" y=\"195\" width=\"550\" height=\"30\" rx=\"4\" fill=\"#ef4444\"/>\n  <text x=\"100\" y=\"215\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" font-weight=\"600\" fill=\"white\">Cards</text>\n  <circle cx=\"600\" cy=\"210\" r=\"12\" fill=\"#dc2626\"/>\n  <text x=\"600\" y=\"214\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"white\">!</text>\n  <text x=\"450\" y=\"205\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\" font-weight=\"600\">Chargeback window (up to 120 days)</text>\n  <text x=\"450\" y=\"218\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#64748b\">Payment can be reversed</text>\n  \n  <!-- Legend -->\n  <rect x=\"50\" y=\"245\" width=\"12\" height=\"12\" rx=\"2\" fill=\"#16a34a\"/>\n  <text x=\"70\" y=\"255\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Strong finality</text>\n  <rect x=\"180\" y=\"245\" width=\"12\" height=\"12\" rx=\"2\" fill=\"#f59e0b\"/>\n  <text x=\"200\" y=\"255\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Moderate</text>\n  <rect x=\"280\" y=\"245\" width=\"12\" height=\"12\" rx=\"2\" fill=\"#ef4444\"/>\n  <text x=\"300\" y=\"255\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Weak finality</text>\n</svg>\n<div class=\"diagram-caption\">PayTo provides near-instant finality; cards remain reversible for months</div>\n</div>\n\n<div class=\"key-point\">\n<div class=\"key-point-title\">💡 Key Insight</div>\n<p style=\"margin-bottom:0\">Finality is a double-edged sword. For legitimate collections, it's a competitive advantage. But it shifts responsibility to you—your merchant onboarding must be robust because there's no chargeback mechanism to catch problems.</p>\n</div>\n\n<!-- PUSH VS PULL -->\n<div class=\"concept\">\n<div class=\"concept-title\">3. Push vs Pull Payments</div>\n<p><strong>Push:</strong> Payer initiates and sends funds (bank transfers, Osko).</p>\n<p><strong>Pull:</strong> Payee initiates collection (direct debits, cards).</p>\n<p><strong>PayTo:</strong> Pull mechanism with payer-authorized agreements managed in banking apps.</p>\n</div>\n\n<!-- PUSH VS PULL DIAGRAM -->\n<div class=\"diagram-container\">\n<div class=\"diagram-title\">Push vs Pull Payment Models</div>\n<svg viewBox=\"0 0 700 350\" xmlns=\"http://www.w3.org/2000/svg\">\n  <!-- Push Payment Section -->\n  <rect x=\"30\" y=\"30\" width=\"300\" height=\"130\" rx=\"12\" fill=\"#f0fdf4\" stroke=\"#86efac\" stroke-width=\"2\"/>\n  <text x=\"180\" y=\"55\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#16a34a\">PUSH PAYMENT</text>\n  \n  <rect x=\"60\" y=\"75\" width=\"80\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#22c55e\" stroke-width=\"2\"/>\n  <text x=\"100\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"20\">👤</text>\n  <text x=\"100\" y=\"120\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">Payer</text>\n  \n  <rect x=\"200\" y=\"75\" width=\"80\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#22c55e\" stroke-width=\"2\"/>\n  <text x=\"240\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"20\">🏪</text>\n  <text x=\"240\" y=\"120\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">Merchant</text>\n  \n  <!-- Push arrow -->\n  <path d=\"M145 105 L195 105\" stroke=\"#16a34a\" stroke-width=\"3\" fill=\"none\" marker-end=\"url(#arrowGreen)\"/>\n  <text x=\"170\" y=\"95\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#16a34a\">Sends $</text>\n  \n  <text x=\"180\" y=\"148\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Payer controls when & how much</text>\n  \n  <!-- Pull Payment Section -->\n  <rect x=\"370\" y=\"30\" width=\"300\" height=\"130\" rx=\"12\" fill=\"#fef3c7\" stroke=\"#fcd34d\" stroke-width=\"2\"/>\n  <text x=\"520\" y=\"55\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#d97706\">PULL PAYMENT</text>\n  \n  <rect x=\"400\" y=\"75\" width=\"80\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#f59e0b\" stroke-width=\"2\"/>\n  <text x=\"440\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"20\">👤</text>\n  <text x=\"440\" y=\"120\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">Payer</text>\n  \n  <rect x=\"540\" y=\"75\" width=\"80\" height=\"60\" rx=\"8\" fill=\"white\" stroke=\"#f59e0b\" stroke-width=\"2\"/>\n  <text x=\"580\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"20\">🏪</text>\n  <text x=\"580\" y=\"120\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">Merchant</text>\n  \n  <!-- Pull arrow -->\n  <path d=\"M535 105 L485 105\" stroke=\"#d97706\" stroke-width=\"3\" fill=\"none\" marker-end=\"url(#arrowOrange)\"/>\n  <text x=\"510\" y=\"95\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#d97706\">Takes $</text>\n  \n  <text x=\"520\" y=\"148\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Merchant initiates collection</text>\n  \n  <!-- PayTo Section -->\n  <rect x=\"150\" y=\"190\" width=\"400\" height=\"140\" rx=\"12\" fill=\"#f0fdfa\" stroke=\"#5eead4\" stroke-width=\"2\"/>\n  <text x=\"350\" y=\"215\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#0d9488\">PAYTO: Pull with Agreement</text>\n  \n  <rect x=\"180\" y=\"235\" width=\"70\" height=\"70\" rx=\"8\" fill=\"white\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n  <text x=\"215\" y=\"262\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"20\">👤</text>\n  <text x=\"215\" y=\"282\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#0f172a\">Customer</text>\n  <text x=\"215\" y=\"293\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">Authorizes</text>\n  \n  <rect x=\"315\" y=\"235\" width=\"70\" height=\"70\" rx=\"8\" fill=\"#ccfbf1\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n  <text x=\"350\" y=\"260\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"16\">📱</text>\n  <text x=\"350\" y=\"280\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#0f172a\">Bank App</text>\n  <text x=\"350\" y=\"293\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">Manages</text>\n  \n  <rect x=\"450\" y=\"235\" width=\"70\" height=\"70\" rx=\"8\" fill=\"white\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n  <text x=\"485\" y=\"262\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"20\">🏪</text>\n  <text x=\"485\" y=\"282\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#0f172a\">Merchant</text>\n  <text x=\"485\" y=\"293\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">Collects</text>\n  \n  <!-- PayTo arrows -->\n  <path d=\"M255 270 L310 270\" stroke=\"#0d9488\" stroke-width=\"2\" stroke-dasharray=\"4,2\"/>\n  <path d=\"M390 270 L445 270\" stroke=\"#0d9488\" stroke-width=\"2\" marker-end=\"url(#arrowTeal)\"/>\n  \n  <text x=\"350\" y=\"320\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0d9488\" font-weight=\"500\">Customer retains visibility & control</text>\n  \n  <!-- Arrow markers -->\n  <defs>\n    <marker id=\"arrowGreen\" markerWidth=\"10\" markerHeight=\"10\" refX=\"9\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L0,6 L9,3 z\" fill=\"#16a34a\"/></marker>\n    <marker id=\"arrowOrange\" markerWidth=\"10\" markerHeight=\"10\" refX=\"9\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L0,6 L9,3 z\" fill=\"#d97706\"/></marker>\n    <marker id=\"arrowTeal\" markerWidth=\"10\" markerHeight=\"10\" refX=\"9\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L0,6 L9,3 z\" fill=\"#0d9488\"/></marker>\n  </defs>\n</svg>\n<div class=\"diagram-caption\">PayTo combines pull payment efficiency with customer control via bank app agreements</div>\n</div>\n\n<h3>Comparing Payment Rails</h3>\n\n<div class=\"example-box\">\n<div class=\"example-label\">Scenario: A Gym Collecting Monthly Memberships</div>\n<table class=\"comparison-table\">\n<tr>\n<th>Aspect</th>\n<th>Cards</th>\n<th>BECS Direct Debit</th>\n<th>PayTo</th>\n</tr>\n<tr>\n<td><strong>Type</strong></td>\n<td>Pull</td>\n<td>Pull</td>\n<td>Pull + Agreement</td>\n</tr>\n<tr>\n<td><strong>Clearing</strong></td>\n<td>Instant</td>\n<td>Batch (days)</td>\n<td>Real-time</td>\n</tr>\n<tr>\n<td><strong>Settlement</strong></td>\n<td>Batched later</td>\n<td>Batched later</td>\n<td>Real-time via RBA</td>\n</tr>\n<tr>\n<td><strong>Finality</strong></td>\n<td>Weak (chargebacks)</td>\n<td>Moderate (indemnity)</td>\n<td>Strong (final)</td>\n</tr>\n<tr>\n<td><strong>Customer Control</strong></td>\n<td>Limited</td>\n<td>Paper DDR</td>\n<td>Bank app management</td>\n</tr>\n</table>\n</div>\n</section>\n\n<!-- AUSTRALIAN ECOSYSTEM -->\n<section class=\"section\">\n<h2>Australia's Payments Ecosystem</h2>\n\n<!-- ECOSYSTEM OVERVIEW DIAGRAM -->\n<div class=\"diagram-container\">\n<div class=\"diagram-title\">Australian Payments Ecosystem Overview</div>\n<svg viewBox=\"0 0 700 400\" xmlns=\"http://www.w3.org/2000/svg\">\n  <!-- Top layer: Regulators -->\n  <rect x=\"50\" y=\"20\" width=\"600\" height=\"70\" rx=\"8\" fill=\"#fef2f2\" stroke=\"#fecaca\"/>\n  <text x=\"350\" y=\"45\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#dc2626\">REGULATORS & POLICY</text>\n  <rect x=\"80\" y=\"55\" width=\"100\" height=\"28\" rx=\"4\" fill=\"white\" stroke=\"#fca5a5\"/>\n  <text x=\"130\" y=\"73\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">RBA / PSB</text>\n  <rect x=\"200\" y=\"55\" width=\"100\" height=\"28\" rx=\"4\" fill=\"white\" stroke=\"#fca5a5\"/>\n  <text x=\"250\" y=\"73\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">ASIC</text>\n  <rect x=\"320\" y=\"55\" width=\"100\" height=\"28\" rx=\"4\" fill=\"white\" stroke=\"#fca5a5\"/>\n  <text x=\"370\" y=\"73\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">AUSTRAC</text>\n  <rect x=\"440\" y=\"55\" width=\"100\" height=\"28\" rx=\"4\" fill=\"white\" stroke=\"#fca5a5\"/>\n  <text x=\"490\" y=\"73\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0f172a\">Treasury</text>\n  \n  <!-- Infrastructure layer -->\n  <rect x=\"50\" y=\"110\" width=\"600\" height=\"80\" rx=\"8\" fill=\"#eff6ff\" stroke=\"#bfdbfe\"/>\n  <text x=\"350\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#2563eb\">INFRASTRUCTURE</text>\n  <rect x=\"80\" y=\"145\" width=\"130\" height=\"35\" rx=\"4\" fill=\"white\" stroke=\"#93c5fd\"/>\n  <text x=\"145\" y=\"160\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" font-weight=\"600\" fill=\"#0f172a\">NPP Platform</text>\n  <text x=\"145\" y=\"173\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">Operated by AP+</text>\n  <rect x=\"230\" y=\"145\" width=\"130\" height=\"35\" rx=\"4\" fill=\"white\" stroke=\"#93c5fd\"/>\n  <text x=\"295\" y=\"160\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" font-weight=\"600\" fill=\"#0f172a\">RBA FSS</text>\n  <text x=\"295\" y=\"173\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">Settlement</text>\n  <rect x=\"380\" y=\"145\" width=\"130\" height=\"35\" rx=\"4\" fill=\"white\" stroke=\"#93c5fd\"/>\n  <text x=\"445\" y=\"160\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" font-weight=\"600\" fill=\"#0f172a\">BECS / DE</text>\n  <text x=\"445\" y=\"173\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">AusPayNet</text>\n  <rect x=\"530\" y=\"145\" width=\"100\" height=\"35\" rx=\"4\" fill=\"white\" stroke=\"#93c5fd\"/>\n  <text x=\"580\" y=\"160\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" font-weight=\"600\" fill=\"#0f172a\">Card Schemes</text>\n  <text x=\"580\" y=\"173\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"8\" fill=\"#64748b\">V/MC/eftpos</text>\n  \n  <!-- Access layer -->\n  <rect x=\"50\" y=\"210\" width=\"600\" height=\"60\" rx=\"8\" fill=\"#f0fdf4\" stroke=\"#bbf7d0\"/>\n  <text x=\"350\" y=\"230\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#16a34a\">ACCESS LAYER</text>\n  <text x=\"350\" y=\"250\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"11\" fill=\"#0f172a\">Banks & NPP Participants (Sponsors)</text>\n  <text x=\"350\" y=\"262\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#64748b\">Provide API access • Hold ESAs at RBA • Set pricing & SLAs</text>\n  \n  <!-- FairPay layer -->\n  <rect x=\"150\" y=\"290\" width=\"400\" height=\"50\" rx=\"8\" fill=\"#0d9488\" stroke=\"#0f766e\" stroke-width=\"2\"/>\n  <text x=\"350\" y=\"315\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"white\">⭐ FAIRPAY</text>\n  <text x=\"350\" y=\"330\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#ccfbf1\">Collections Enablement Platform</text>\n  \n  <!-- Merchant layer -->\n  <rect x=\"50\" y=\"360\" width=\"600\" height=\"35\" rx=\"8\" fill=\"#faf5ff\" stroke=\"#e9d5ff\"/>\n  <text x=\"130\" y=\"382\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#7c3aed\">SMBs</text>\n  <text x=\"270\" y=\"382\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#7c3aed\">B2B / SaaS</text>\n  <text x=\"420\" y=\"382\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#7c3aed\">Gig / Marketplaces</text>\n  <text x=\"570\" y=\"382\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#7c3aed\">Charities / NFPs</text>\n  \n  <!-- Connecting arrows -->\n  <path d=\"M350 270 L350 288\" stroke=\"#64748b\" stroke-width=\"2\" marker-end=\"url(#arrowGray)\"/>\n  <path d=\"M350 340 L350 358\" stroke=\"#64748b\" stroke-width=\"2\" marker-end=\"url(#arrowGray)\"/>\n  \n  <defs>\n    <marker id=\"arrowGray\" markerWidth=\"10\" markerHeight=\"10\" refX=\"9\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L0,6 L9,3 z\" fill=\"#64748b\"/></marker>\n  </defs>\n</svg>\n<div class=\"diagram-caption\">FairPay sits in the enablement layer, connecting merchants to infrastructure via sponsor relationships</div>\n</div>\n\n<div class=\"institution\">\n<div class=\"institution-header\">\n<div class=\"institution-name\">Reserve Bank of Australia (RBA)</div>\n<div class=\"institution-type\">Regulator & Infrastructure</div>\n</div>\n<div class=\"institution-role\">Through its <strong>Payments System Board</strong>, sets policy for efficiency, competition, and resilience. Operates the <strong>Fast Settlement Service (FSS)</strong> for real-time NPP settlement.</div>\n<div class=\"institution-relevance\"><strong>FairPay relevance:</strong> The RBA shapes your environment. March 2026 update signals card cost changes coming by end-March. They also focus on resilience—think about your uptime and failover.</div>\n</div>\n\n<div class=\"institution\">\n<div class=\"institution-header\">\n<div class=\"institution-name\">Australian Payments Plus (AP+)</div>\n<div class=\"institution-type\">Infrastructure Operator</div>\n</div>\n<div class=\"institution-role\">Operates <strong>NPP \"The Platform\"</strong> (ISO 20022, 24/7, PayID, PayTo), <strong>eftpos</strong>, and <strong>BPAY</strong>.</div>\n<div class=\"institution-relevance\"><strong>FairPay relevance:</strong> Fundamental to your PayTo business. You connect through a participant, but understanding the platform shapes your product possibilities.</div>\n</div>\n\n<div class=\"institution\">\n<div class=\"institution-header\">\n<div class=\"institution-name\">AusPayNet</div>\n<div class=\"institution-type\">Industry Body</div>\n</div>\n<div class=\"institution-role\">Administers <strong>Direct Entry/BECS</strong>—legacy batch payments since the 1990s. Publishes fraud statistics.</div>\n<div class=\"institution-relevance\"><strong>FairPay relevance:</strong> BECS is how most direct debits work today. 2030 end-date removed—you'll need compatibility for transitioning merchants.</div>\n</div>\n\n<h3>Control Points</h3>\n\n<!-- CONTROL POINTS DIAGRAM -->\n<div class=\"diagram-container\">\n<div class=\"diagram-title\">Where Power Sits in the Ecosystem</div>\n<svg viewBox=\"0 0 700 200\" xmlns=\"http://www.w3.org/2000/svg\">\n  <!-- Four control points -->\n  <rect x=\"30\" y=\"40\" width=\"145\" height=\"140\" rx=\"12\" fill=\"#f0fdfa\" stroke=\"#99f6e4\" stroke-width=\"2\"/>\n  <text x=\"102\" y=\"70\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"24\">🔑</text>\n  <text x=\"102\" y=\"95\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#0d9488\">Access</text>\n  <text x=\"102\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Who can connect</text>\n  <text x=\"102\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">to NPP? Through</text>\n  <text x=\"102\" y=\"145\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">sponsors only.</text>\n  \n  <rect x=\"195\" y=\"40\" width=\"145\" height=\"140\" rx=\"12\" fill=\"#fef3c7\" stroke=\"#fcd34d\" stroke-width=\"2\"/>\n  <text x=\"267\" y=\"70\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"24\">💰</text>\n  <text x=\"267\" y=\"95\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#d97706\">Pricing</text>\n  <text x=\"267\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">PayTo fees via</text>\n  <text x=\"267\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">AP+ → sponsors.</text>\n  <text x=\"267\" y=\"145\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">Your margin on top.</text>\n  \n  <rect x=\"360\" y=\"40\" width=\"145\" height=\"140\" rx=\"12\" fill=\"#eff6ff\" stroke=\"#93c5fd\" stroke-width=\"2\"/>\n  <text x=\"432\" y=\"70\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"24\">📊</text>\n  <text x=\"432\" y=\"95\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#2563eb\">Data</text>\n  <text x=\"432\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">ISO 20022 rich</text>\n  <text x=\"432\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">data flows. Who</text>\n  <text x=\"432\" y=\"145\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">can use it?</text>\n  \n  <rect x=\"525\" y=\"40\" width=\"145\" height=\"140\" rx=\"12\" fill=\"#fef2f2\" stroke=\"#fecaca\" stroke-width=\"2\"/>\n  <text x=\"597\" y=\"70\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"24\">⚖️</text>\n  <text x=\"597\" y=\"95\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"12\" font-weight=\"600\" fill=\"#dc2626\">Liability</text>\n  <text x=\"597\" y=\"115\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">When fraud or</text>\n  <text x=\"597\" y=\"130\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">disputes occur,</text>\n  <text x=\"597\" y=\"145\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#64748b\">who bears cost?</text>\n</svg>\n</div>\n</section>\n\n<!-- POSITIONING OPTIONS -->\n<section class=\"section\">\n<h2>FairPay Positioning Options</h2>\n\n<!-- POSITIONING OPTIONS DIAGRAM -->\n<div class=\"diagram-container\">\n<div class=\"diagram-title\">Three Strategic Positioning Options</div>\n<svg viewBox=\"0 0 700 320\" xmlns=\"http://www.w3.org/2000/svg\">\n  <!-- Option 1 -->\n  <rect x=\"30\" y=\"30\" width=\"200\" height=\"260\" rx=\"12\" fill=\"#f0fdf4\" stroke=\"#86efac\" stroke-width=\"2\"/>\n  <rect x=\"30\" y=\"30\" width=\"200\" height=\"45\" rx=\"12\" fill=\"#22c55e\"/>\n  <rect x=\"30\" y=\"63\" width=\"200\" height=\"12\" fill=\"#22c55e\"/>\n  <text x=\"130\" y=\"58\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"13\" font-weight=\"600\" fill=\"white\">Option 1</text>\n  <text x=\"130\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#0f172a\">Pure API Layer</text>\n  \n  <text x=\"50\" y=\"130\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"65\" y=\"130\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Lighter compliance</text>\n  <text x=\"50\" y=\"148\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"65\" y=\"148\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Faster to launch</text>\n  <text x=\"50\" y=\"166\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"65\" y=\"166\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Lower capital needs</text>\n  \n  <text x=\"50\" y=\"195\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">✗</text>\n  <text x=\"65\" y=\"195\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Lower margins</text>\n  <text x=\"50\" y=\"213\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">✗</text>\n  <text x=\"65\" y=\"213\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Sponsor dependent</text>\n  \n  <rect x=\"50\" y=\"235\" width=\"160\" height=\"40\" rx=\"6\" fill=\"#dcfce7\"/>\n  <text x=\"130\" y=\"258\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\" font-weight=\"600\">Best for: Pre-revenue</text>\n  <text x=\"130\" y=\"270\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#16a34a\">Prove demand first</text>\n  \n  <!-- Option 2 -->\n  <rect x=\"250\" y=\"30\" width=\"200\" height=\"260\" rx=\"12\" fill=\"#fef3c7\" stroke=\"#fcd34d\" stroke-width=\"2\"/>\n  <rect x=\"250\" y=\"30\" width=\"200\" height=\"45\" rx=\"12\" fill=\"#f59e0b\"/>\n  <rect x=\"250\" y=\"63\" width=\"200\" height=\"12\" fill=\"#f59e0b\"/>\n  <text x=\"350\" y=\"58\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"13\" font-weight=\"600\" fill=\"white\">Option 2</text>\n  <text x=\"350\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#0f172a\">Funds Flow Manager</text>\n  \n  <text x=\"270\" y=\"130\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"285\" y=\"130\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">More control & margin</text>\n  <text x=\"270\" y=\"148\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"285\" y=\"148\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Product flexibility</text>\n  <text x=\"270\" y=\"166\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"285\" y=\"166\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Manage splits/payouts</text>\n  \n  <text x=\"270\" y=\"195\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">✗</text>\n  <text x=\"285\" y=\"195\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Treasury licensing</text>\n  <text x=\"270\" y=\"213\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">✗</text>\n  <text x=\"285\" y=\"213\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Safeguarding required</text>\n  \n  <rect x=\"270\" y=\"235\" width=\"160\" height=\"40\" rx=\"6\" fill=\"#fef9c3\"/>\n  <text x=\"350\" y=\"258\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#ca8a04\" font-weight=\"600\">Best for: Marketplaces</text>\n  <text x=\"350\" y=\"270\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#ca8a04\">Gig economy, splits</text>\n  \n  <!-- Option 3 -->\n  <rect x=\"470\" y=\"30\" width=\"200\" height=\"260\" rx=\"12\" fill=\"#f0fdfa\" stroke=\"#5eead4\" stroke-width=\"2\"/>\n  <rect x=\"470\" y=\"30\" width=\"200\" height=\"45\" rx=\"12\" fill=\"#0d9488\"/>\n  <rect x=\"470\" y=\"63\" width=\"200\" height=\"12\" fill=\"#0d9488\"/>\n  <text x=\"570\" y=\"58\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"13\" font-weight=\"600\" fill=\"white\">Option 3</text>\n  <text x=\"570\" y=\"100\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"14\" font-weight=\"600\" fill=\"#0f172a\">Vertical Specialist</text>\n  \n  <text x=\"490\" y=\"130\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"505\" y=\"130\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Domain expertise moat</text>\n  <text x=\"490\" y=\"148\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"505\" y=\"148\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Focused go-to-market</text>\n  <text x=\"490\" y=\"166\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#16a34a\">✓</text>\n  <text x=\"505\" y=\"166\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Deep integrations</text>\n  \n  <text x=\"490\" y=\"195\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">✗</text>\n  <text x=\"505\" y=\"195\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Smaller TAM</text>\n  <text x=\"490\" y=\"213\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#dc2626\">✗</text>\n  <text x=\"505\" y=\"213\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#475569\">Vertical knowledge req.</text>\n  \n  <rect x=\"490\" y=\"235\" width=\"160\" height=\"40\" rx=\"6\" fill=\"#ccfbf1\"/>\n  <text x=\"570\" y=\"258\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"10\" fill=\"#0d9488\" font-weight=\"600\">Best for: Deep niches</text>\n  <text x=\"570\" y=\"270\" text-anchor=\"middle\" font-family=\"DM Sans\" font-size=\"9\" fill=\"#0d9488\">Charities, gyms, etc.</text>\n</svg>\n</div>\n\n<div class=\"key-point\">\n<div class=\"key-point-title\">💡 Recommendation for FairPay</div>\n<p style=\"margin-bottom:0\">Start with Option 1 architecture, design with Option 2 in mind. Prove demand, learn what merchants need, build compliance progressively. Use Option 3 as a go-to-market strategy even if your infrastructure is horizontal.</p>\n</div>\n</section>\n\n<!-- REQUIRED READINGS -->\n<section class=\"section\">\n<h2>Required Readings</h2>\n<p>Primary Australian sources. Budget 45-60 minutes total.</p>\n\n<a href=\"https://www.auspayplus.com.au/brands/npp-the-platform\" target=\"_blank\" class=\"resource\">\n<span class=\"resource-num\">1</span>\n<div class=\"resource-content\">\n<div class=\"resource-title\">NPP \"The Platform\" Overview</div>\n<div class=\"resource-desc\">How NPP works: ISO 20022, 24/7 availability, PayID, settlement via RBA FSS.</div>\n<div class=\"resource-time\">📖 15-20 min</div>\n</div>\n</a>\n\n<a href=\"https://www.auspaynet.com.au/resources/direct-entry\" target=\"_blank\" class=\"resource\">\n<span class=\"resource-num\">2</span>\n<div class=\"resource-content\">\n<div class=\"resource-title\">Direct Entry / BECS Explainer</div>\n<div class=\"resource-desc\">Understanding the legacy batch system and its limitations.</div>\n<div class=\"resource-time\">📖 10-15 min</div>\n</div>\n</a>\n\n<a href=\"https://www.rba.gov.au/media-releases/2026/mr-26-06.html\" target=\"_blank\" class=\"resource\">\n<span class=\"resource-num\">3</span>\n<div class=\"resource-content\">\n<div class=\"resource-title\">Payments System Board Update: March 2026</div>\n<div class=\"resource-desc\">Current RBA priorities and regulatory direction.</div>\n<div class=\"resource-time\">📖 15-20 min</div>\n</div>\n</a>\n</section>\n\n<!-- QUIZ -->\n<section class=\"section\">\n<h2>Knowledge Check</h2>\n\n<div class=\"quiz-container\">\n<div class=\"quiz-intro\">\n<p style=\"margin:0\"><strong>8 questions</strong> • Open book • Instant feedback</p>\n</div>\n\n<div class=\"q\" data-correct=\"1\">\n<div class=\"q-num\">Question 1 of 8</div>\n<div class=\"q-text\">What is the key difference between clearing and settlement?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q1\" value=\"0\"><span>Clearing is for cards, settlement is for bank transfers</span></label>\n<label><input type=\"radio\" name=\"q1\" value=\"1\"><span>Clearing exchanges payment instructions; settlement moves actual funds</span></label>\n<label><input type=\"radio\" name=\"q1\" value=\"2\"><span>They are the same thing</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"2\">\n<div class=\"q-num\">Question 2 of 8</div>\n<div class=\"q-text\">Where does final settlement for NPP payments occur?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q2\" value=\"0\"><span>At the merchant's bank</span></label>\n<label><input type=\"radio\" name=\"q2\" value=\"1\"><span>Through Visa/Mastercard</span></label>\n<label><input type=\"radio\" name=\"q2\" value=\"2\"><span>At the RBA via Exchange Settlement Accounts (ESAs)</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"0\">\n<div class=\"q-num\">Question 3 of 8</div>\n<div class=\"q-text\">PayTo is best described as:</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q3\" value=\"0\"><span>Pull payment with payer-authorized agreements</span></label>\n<label><input type=\"radio\" name=\"q3\" value=\"1\"><span>Push payment initiated by the payer</span></label>\n<label><input type=\"radio\" name=\"q3\" value=\"2\"><span>Batch payment processed overnight</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"1\">\n<div class=\"q-num\">Question 4 of 8</div>\n<div class=\"q-text\">Which organization operates the NPP platform?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q4\" value=\"0\"><span>Reserve Bank of Australia</span></label>\n<label><input type=\"radio\" name=\"q4\" value=\"1\"><span>Australian Payments Plus (AP+)</span></label>\n<label><input type=\"radio\" name=\"q4\" value=\"2\"><span>AusPayNet</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"2\">\n<div class=\"q-num\">Question 5 of 8</div>\n<div class=\"q-text\">What does \"finality\" mean in payments?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q5\" value=\"0\"><span>The payment has been initiated</span></label>\n<label><input type=\"radio\" name=\"q5\" value=\"1\"><span>The merchant received notification</span></label>\n<label><input type=\"radio\" name=\"q5\" value=\"2\"><span>The payment is irrevocable—neither party can reverse it</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"2\">\n<div class=\"q-num\">Question 6 of 8</div>\n<div class=\"q-text\">What happened to the planned 2030 BECS end-date?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q6\" value=\"0\"><span>It was confirmed</span></label>\n<label><input type=\"radio\" name=\"q6\" value=\"1\"><span>It was moved earlier</span></label>\n<label><input type=\"radio\" name=\"q6\" value=\"2\"><span>It was removed</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"0\">\n<div class=\"q-num\">Question 7 of 8</div>\n<div class=\"q-text\">Which messaging standard does the NPP use?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q7\" value=\"0\"><span>ISO 20022</span></label>\n<label><input type=\"radio\" name=\"q7\" value=\"1\"><span>SWIFT MT</span></label>\n<label><input type=\"radio\" name=\"q7\" value=\"2\"><span>Fixed-width files</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<div class=\"q\" data-correct=\"1\">\n<div class=\"q-num\">Question 8 of 8</div>\n<div class=\"q-text\">How would FairPay typically access the NPP?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q8\" value=\"0\"><span>Direct connection to RBA</span></label>\n<label><input type=\"radio\" name=\"q8\" value=\"1\"><span>Through a sponsoring NPP participant</span></label>\n<label><input type=\"radio\" name=\"q8\" value=\"2\"><span>By becoming a card scheme member</span></label>\n</div>\n<div class=\"feedback\"></div>\n</div>\n\n<button class=\"btn\" onclick=\"checkQuiz()\">Check My Answers</button>\n\n<div class=\"score-display\" id=\"score-display\">\n<div class=\"score-num\" id=\"score-num\">0/8</div>\n<div class=\"score-label\">Questions Correct</div>\n<div class=\"score-message\" id=\"score-message\"></div>\n</div>\n</div>\n</section>\n\n<!-- DELIVERABLE -->\n<section class=\"section\">\n<div class=\"deliverable\">\n<h3>📋 Week 1 Deliverable</h3>\n<p style=\"margin-bottom:1.5rem\">Complete these for your capstone (Slides 1-2):</p>\n<ul class=\"checklist\">\n<li><strong>Ecosystem Map (1 slide)</strong><br>Draw FairPay's position—who you connect to, where money flows, where data flows, where liability sits.</li>\n<li><strong>Positioning Hypothesis (½ page)</strong><br>Which option are you pursuing first? Why? What would change your mind?</li>\n<li><strong>Decision Backlog (list)</strong><br>3 payments decisions you need to make in the next 90 days.</li>\n</ul>\n</div>\n</section>\n\n<div class=\"nav-footer\">\n<a href=\"../index.html\" class=\"nav-btn\">← Course Home</a>\n<a href=\"week2.html\" class=\"nav-btn primary\">Continue to Week 2 →</a>\n</div>\n\n</div>\n\n<script>\nconst answers={q1:{correct:'1',exp:'Clearing exchanges instructions; settlement moves actual funds.'},q2:{correct:'2',exp:'NPP settles via RBA Fast Settlement Service in Exchange Settlement Accounts.'},q3:{correct:'0',exp:'PayTo is pull payment with payer-authorized agreements in banking apps.'},q4:{correct:'1',exp:'AP+ operates NPP. RBA operates the Fast Settlement Service.'},q5:{correct:'2',exp:'Finality means irrevocable—neither party can reverse.'},q6:{correct:'2',exp:'The 2030 end-date was removed. Transition is now market-driven.'},q7:{correct:'0',exp:'NPP uses ISO 20022 for rich, structured data.'},q8:{correct:'1',exp:'Startups access NPP through sponsoring participants.'}};\nfunction checkQuiz(){let s=0;document.querySelectorAll('.q').forEach((q,i)=>{const n='q'+(i+1),sel=q.querySelector('input:checked'),fb=q.querySelector('.feedback');q.querySelectorAll('label').forEach(l=>l.style.background='');if(sel){if(sel.value===answers[n].correct){s++;fb.className='feedback correct';fb.innerHTML='✓ '+answers[n].exp;sel.parentElement.style.background='rgba(22,163,74,.1)';}else{fb.className='feedback incorrect';fb.innerHTML='✗ '+answers[n].exp;sel.parentElement.style.background='rgba(234,88,12,.1)';}}});document.getElementById('score-num').textContent=s+'/8';document.getElementById('score-message').innerHTML=s>=6?'🎉 Great work! Ready for Week 2.':'📖 Review concepts and try again.';document.getElementById('score-display').classList.add('visible');}\n</script>\n</body>\n</html>\n\n\n--- WEEK 2 CONTENT ---\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Week 2: Rails Selection & A2A | FairPay CEO Course</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--bg:#ffffff;--card:#f8fafc;--elevated:#f1f5f9;--teal:#14b8a6;--teal-dim:rgba(20,184,166,.15);--orange:#f97316;--text:#0f172a;--text2:#475569;--muted:#64748b;--border:#e2e8f0;--success:#22c55e}\n*{margin:0;padding:0;box-sizing:border-box}\nbody{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);line-height:1.7}\n.nav{position:sticky;top:0;background:rgba(255,255,255,.95);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;justify-content:space-between}\n.nav a{color:var(--text2);text-decoration:none}.nav a:hover{color:var(--teal)}\n.hero{padding:3rem 2rem;background:linear-gradient(180deg,rgba(20,184,166,.08),transparent);border-bottom:1px solid var(--border);text-align:center}\n.week-label{display:inline-block;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--teal);background:var(--teal-dim);padding:.5rem 1rem;border-radius:2rem;margin-bottom:1rem}\nh1{font-family:'Instrument Serif',serif;font-size:2.5rem;margin-bottom:1rem}\n.subtitle{color:var(--text2);max-width:700px;margin:0 auto}\n.container{max-width:900px;margin:0 auto;padding:2rem}\n.section{margin-bottom:3rem}\nh2{font-family:'Instrument Serif',serif;font-size:1.5rem;margin-bottom:1rem;color:var(--teal)}\nh3{font-size:1.1rem;margin:1.5rem 0 .75rem}\np{margin-bottom:1rem;color:var(--text2)}\n.card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1rem}\n.concept{background:var(--elevated);border-left:3px solid var(--teal);padding:1rem;margin-bottom:1rem;border-radius:0 8px 8px 0}\n.concept b{color:var(--teal)}\ntable{width:100%;border-collapse:collapse;margin:1rem 0;font-size:.9rem}\nth,td{padding:.75rem;text-align:left;border:1px solid var(--border)}\nth{background:var(--elevated);color:var(--teal)}\ntd{color:var(--text2)}\n.resource{display:block;padding:1rem;background:var(--elevated);border:1px solid var(--border);border-radius:8px;margin-bottom:.5rem;text-decoration:none;color:var(--text)}\n.resource:hover{border-color:var(--teal)}\n.resource small{color:var(--muted)}\n.quiz{margin-top:1rem}\n.q{margin-bottom:1.5rem;padding-bottom:1.5rem;border-bottom:1px solid var(--border)}\n.q:last-child{border:none}\n.q-text{font-weight:500;margin-bottom:.75rem}\n.opts label{display:block;padding:.5rem .75rem;margin:.25rem 0;background:var(--elevated);border:1px solid var(--border);border-radius:6px;cursor:pointer}\n.opts label:hover{border-color:var(--teal)}\n.opts input{margin-right:.5rem}\n.btn{background:var(--teal);color:#fff;border:none;padding:.75rem 1.5rem;border-radius:8px;cursor:pointer;font-weight:600;margin-top:1rem}\n#result{margin-top:1rem;padding:1rem;border-radius:8px;display:none}\n.deliverable{background:linear-gradient(135deg,rgba(20,184,166,.1),rgba(20,184,166,.02));border:1px solid var(--teal);border-radius:12px;padding:1.5rem}\n.checklist{list-style:none;padding:0}\n.checklist li{padding:.5rem 0;border-bottom:1px solid var(--border);color:var(--text2)}\n.checklist li:last-child{border:none}\n.nav-footer{display:flex;justify-content:space-between;margin-top:3rem;padding-top:2rem;border-top:1px solid var(--border)}\n.nav-btn{padding:.75rem 1.5rem;background:var(--card);border:1px solid var(--border);border-radius:8px;text-decoration:none;color:var(--text2)}\n.nav-btn:hover{border-color:var(--teal);color:var(--text)}\n</style>\n</head>\n<body>\n<nav class=\"nav\"><a href=\"week1.html\">← Week 1</a><span style=\"color:var(--text);font-weight:600\">Week 2 of 6</span><a href=\"week3.html\">Week 3 →</a></nav>\n\n<header class=\"hero\">\n<span class=\"week-label\">Week 2</span>\n<h1>Rails Selection & Account-to-Account</h1>\n<p class=\"subtitle\">Deep dive into NPP, PayTo, and BECS. Build your rail decision matrix.</p>\n</header>\n\n<div class=\"container\">\n\n<section class=\"section\">\n<h2>Learning Objectives</h2>\n<div class=\"card\">\n<ul style=\"color:var(--text2);padding-left:1.5rem\">\n<li>Apply an 8-criteria framework for rail selection</li>\n<li>Understand NPP architecture and PayTo agreement lifecycle</li>\n<li>Explain BECS limitations and transition uncertainty</li>\n<li>Build a rail decision matrix for FairPay use cases</li>\n<li>Create an A2A roadmap balancing PayTo-first with BECS compatibility</li>\n</ul>\n</div>\n</section>\n\n<section class=\"section\">\n<h2>Rail Selection Framework</h2>\n<p>Eight criteria for comparing payment rails:</p>\n\n<div class=\"concept\"><b>1. Availability</b> — When can transactions happen? NPP is 24/7/365 real-time. BECS is batch (days). Cards are near real-time.</div>\n<div class=\"concept\"><b>2. Data Richness</b> — What information travels with payment? NPP uses ISO 20022 (rich, structured). BECS has 18 characters. Big difference for reconciliation.</div>\n<div class=\"concept\"><b>3. Authorization Model</b> — How does payer consent? PayTo: bank app agreements. BECS: DDR forms. Cards: card-on-file.</div>\n<div class=\"concept\"><b>4. Reversibility</b> — Can payments be reversed? Cards: chargebacks (months). BECS: indemnity claims. PayTo: final once settled.</div>\n<div class=\"concept\"><b>5. Fraud Posture</b> — Where does fraud risk sit? Cards have high CNP fraud ($816M in 2024). PayTo shifts model—customer authorizes with bank security.</div>\n<div class=\"concept\"><b>6. Integration Burden</b> — How hard to build/maintain? Cards: mature SDKs. BECS: batch files. NPP/PayTo: newer, evolving APIs.</div>\n<div class=\"concept\"><b>7. Unit Economics</b> — Cost per transaction? Cards: interchange + scheme fees + acquirer margin. BECS: very cheap. PayTo: low-moderate.</div>\n<div class=\"concept\"><b>8. Access Constraints</b> — How do you get on? All require sponsor/partner relationships.</div>\n</section>\n\n<section class=\"section\">\n<h2>Rail Comparison Matrix</h2>\n<div style=\"overflow-x:auto\">\n<table>\n<tr><th>Criteria</th><th>NPP / PayTo</th><th>BECS</th><th>Cards (CNP)</th></tr>\n<tr><td>Availability</td><td>24/7 real-time</td><td>Batch (days)</td><td>Near real-time</td></tr>\n<tr><td>Data</td><td>ISO 20022 rich</td><td>18 chars</td><td>Moderate</td></tr>\n<tr><td>Authorization</td><td>Bank app</td><td>DDR forms</td><td>Card-on-file</td></tr>\n<tr><td>Reversibility</td><td>Final</td><td>Indemnity claims</td><td>Chargebacks</td></tr>\n<tr><td>Fraud profile</td><td>Customer controls</td><td>Unauthorized risk</td><td>High CNP</td></tr>\n<tr><td>Cost</td><td>Low-moderate</td><td>Very low</td><td>High</td></tr>\n</table>\n</div>\n</section>\n\n<section class=\"section\">\n<h2>NPP & PayTo Deep Dive</h2>\n\n<div class=\"concept\">\n<b>NPP Architecture</b><br>\nISO 20022 messaging • Payment Access Gateways (PAGs) • 24/7/365 availability • Settlement via RBA Fast Settlement Service in central bank funds • PayID addressing\n</div>\n\n<div class=\"concept\">\n<b>PayTo Agreement Lifecycle</b><br>\n<strong>Created</strong> (pending authorization) → <strong>Active</strong> (customer approved in bank app) → <strong>Suspended</strong> (paused by either party) → <strong>Cancelled</strong> (terminated)<br>\nYour system must track these states and handle transitions gracefully.\n</div>\n\n<div class=\"concept\">\n<b>BECS Reality</b><br>\nStill processes huge volumes. Most existing direct debits run on BECS. The 2030 end-date was removed—transition is market-driven, not deadline-driven. <strong>FairPay strategy:</strong> Lead with PayTo, maintain BECS compatibility, don't over-invest in BECS innovation.\n</div>\n</section>\n\n<section class=\"section\">\n<h2>Required Readings</h2>\n<a href=\"https://www.auspayplus.com.au/solutions/payto\" target=\"_blank\" class=\"resource\">\n<strong>1. PayTo Overview</strong><br><small>AP+ — Agreements, authorization, control</small>\n</a>\n<a href=\"https://www.auspayplus.com.au/brands/npp-the-platform\" target=\"_blank\" class=\"resource\">\n<strong>2. NPP Platform (Review)</strong><br><small>AP+ — Technical architecture</small>\n</a>\n<a href=\"https://www.rba.gov.au/media-releases/2026/mr-26-06.html\" target=\"_blank\" class=\"resource\">\n<strong>3. PSB March 2026 (A2A section)</strong><br><small>RBA — Transition commentary</small>\n</a>\n</section>\n\n<section class=\"section\">\n<h2>Knowledge Check</h2>\n<div class=\"card\">\n<div class=\"quiz\" id=\"quiz\">\n<div class=\"q\" data-correct=\"2\">\n<div class=\"q-text\">1. What is PayTo's key advantage over BECS for subscriptions?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q1\" value=\"0\">No transaction fees</label>\n<label><input type=\"radio\" name=\"q1\" value=\"1\">Older and more established</label>\n<label><input type=\"radio\" name=\"q1\" value=\"2\">Real-time confirmation vs batch delays</label>\n</div>\n</div>\n<div class=\"q\" data-correct=\"1\">\n<div class=\"q-text\">2. How are PayTo agreements managed by customers?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q2\" value=\"0\">Through paper forms</label>\n<label><input type=\"radio\" name=\"q2\" value=\"1\">In their banking app—view, pause, cancel</label>\n<label><input type=\"radio\" name=\"q2\" value=\"2\">Through the merchant only</label>\n</div>\n</div>\n<div class=\"q\" data-correct=\"0\">\n<div class=\"q-text\">3. What messaging standard does NPP use?</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q3\" value=\"0\">ISO 20022</label>\n<label><input type=\"radio\" name=\"q3\" value=\"1\">SWIFT MT</label>\n<label><input type=\"radio\" name=\"q3\" value=\"2\">Fixed-width files</label>\n</div>\n</div>\n<div class=\"q\" data-correct=\"2\">\n<div class=\"q-text\">4. BECS data descriptions are limited to:</div>\n<div class=\"opts\">\n<label><input type=\"radio\" name=\"q4\" value=\"0\">256 characters</label>\n<label><input type=\"radio\" name=\"q4\" value=\"1\">100 characters</label>\n<label><input type=\"radio\" name=\"q4\" value=\"2\">18 characters</label>\n</div>\n</div>\n</div>\n<button class=\"btn\" onclick=\"checkQuiz()\">Check Answers</button>\n<div id=\"result\"></div>\n</div>\n</section>\n\n<section class=\"section\">\n<div class=\"deliverable\">\n<h3>📋 Week 2 Deliverable</h3>\n<p>Build these for your capstone (Slides 3-4):</p>\n<ul class=\"checklist\">\n<li>☐ <strong>Rail Decision Matrix (1 slide):</strong> Apply 8 criteria to FairPay's top 2 use cases (e.g., gym memberships + B2B invoicing)</li>\n<li>☐ <strong>A2A Roadmap Hypothesis (½ page):</strong> What to build now (PayTo-first), what to maintain (BECS), what to avoid, key assumptions</li>\n</ul>\n</div>\n</section>\n\n<div class=\"nav-footer\">\n<a href=\"week1.html\" class=\"nav-btn\">← Week 1</a>\n<a href=\"week3.html\" class=\"nav-btn\">Week 3: Cards & Stack →</a>\n</div>\n</div>\n\n<script>\nfunction checkQuiz(){\nlet score=0,total=4;\ndocument.querySelectorAll('.q').forEach(q=>{\nconst correct=q.dataset.correct;\nconst selected=q.querySelector('input:checked');\nif(selected&&selected.value===correct)score++;\n});\nconst r=document.getElementById('result');\nr.style.display='block';\nr.style.background=score>=3?'rgba(34,197,94,.15)':'rgba(249,115,22,.15)';\nr.innerHTML='<strong>Score: '+score+'/'+total+'</strong>';\n}\n</script>\n</body>\n</html>\n\n\n--- WEEK 3 CONTENT ---\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Week 3: Cards & Processing Stack | FairPay CEO Course</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--bg:#ffffff;--card:#f8fafc;--elevated:#f1f5f9;--teal:#14b8a6;--teal-dim:rgba(20,184,166,.15);--orange:#f97316;--text:#0f172a;--text2:#475569;--muted:#64748b;--border:#e2e8f0;--success:#22c55e}\n*{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);line-height:1.7}\n.nav{position:sticky;top:0;background:rgba(255,255,255,.95);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;justify-content:space-between}\n.nav a{color:var(--text2);text-decoration:none}.nav a:hover{color:var(--teal)}\n.hero{padding:3rem 2rem;background:linear-gradient(180deg,rgba(20,184,166,.08),transparent);border-bottom:1px solid var(--border);text-align:center}\n.week-label{display:inline-block;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--teal);background:var(--teal-dim);padding:.5rem 1rem;border-radius:2rem;margin-bottom:1rem}\nh1{font-family:'Instrument Serif',serif;font-size:2.5rem;margin-bottom:1rem}\n.subtitle{color:var(--text2);max-width:700px;margin:0 auto}\n.container{max-width:900px;margin:0 auto;padding:2rem}\n.section{margin-bottom:3rem}h2{font-family:'Instrument Serif',serif;font-size:1.5rem;margin-bottom:1rem;color:var(--teal)}\nh3{font-size:1.1rem;margin:1.5rem 0 .75rem}p{margin-bottom:1rem;color:var(--text2)}\n.card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1rem}\n.concept{background:var(--elevated);border-left:3px solid var(--teal);padding:1rem;margin-bottom:1rem;border-radius:0 8px 8px 0}.concept b{color:var(--teal)}\n.resource{display:block;padding:1rem;background:var(--elevated);border:1px solid var(--border);border-radius:8px;margin-bottom:.5rem;text-decoration:none;color:var(--text)}.resource:hover{border-color:var(--teal)}.resource small{color:var(--muted)}\n.quiz{margin-top:1rem}.q{margin-bottom:1.5rem;padding-bottom:1.5rem;border-bottom:1px solid var(--border)}.q:last-child{border:none}.q-text{font-weight:500;margin-bottom:.75rem}\n.opts label{display:block;padding:.5rem .75rem;margin:.25rem 0;background:var(--elevated);border:1px solid var(--border);border-radius:6px;cursor:pointer}.opts label:hover{border-color:var(--teal)}.opts input{margin-right:.5rem}\n.btn{background:var(--teal);color:#fff;border:none;padding:.75rem 1.5rem;border-radius:8px;cursor:pointer;font-weight:600;margin-top:1rem}\n#result{margin-top:1rem;padding:1rem;border-radius:8px;display:none}\n.deliverable{background:linear-gradient(135deg,rgba(20,184,166,.1),rgba(20,184,166,.02));border:1px solid var(--teal);border-radius:12px;padding:1.5rem}\n.checklist{list-style:none;padding:0}.checklist li{padding:.5rem 0;border-bottom:1px solid var(--border);color:var(--text2)}.checklist li:last-child{border:none}\n.nav-footer{display:flex;justify-content:space-between;margin-top:3rem;padding-top:2rem;border-top:1px solid var(--border)}\n.nav-btn{padding:.75rem 1.5rem;background:var(--card);border:1px solid var(--border);border-radius:8px;text-decoration:none;color:var(--text2)}.nav-btn:hover{border-color:var(--teal);color:var(--text)}\n.stack-layer{background:var(--elevated);border:1px solid var(--border);padding:1rem;margin:.5rem 0;border-radius:8px;display:flex;justify-content:space-between;align-items:center}\n.stack-layer .name{font-weight:600;color:var(--text)}.stack-layer .decision{font-size:.85rem;color:var(--teal)}\n</style>\n</head>\n<body>\n<nav class=\"nav\"><a href=\"week2.html\">← Week 2</a><span style=\"color:var(--text);font-weight:600\">Week 3 of 6</span><a href=\"week4.html\">Week 4 →</a></nav>\n<header class=\"hero\"><span class=\"week-label\">Week 3</span><h1>Cards & Processing Stack</h1><p class=\"subtitle\">Understand card economics and map FairPay's technical architecture.</p></header>\n<div class=\"container\">\n\n<section class=\"section\">\n<h2>Learning Objectives</h2>\n<div class=\"card\"><ul style=\"color:var(--text2);padding-left:1.5rem\">\n<li>Understand card economics: interchange, scheme fees, acquirer margin</li>\n<li>Explain least-cost routing and RBA benchmarks</li>\n<li>Map the payments technology stack layers</li>\n<li>Make informed build vs partner decisions for each layer</li>\n</ul></div>\n</section>\n\n<section class=\"section\">\n<h2>Card Economics</h2>\n<p>Even as a PayTo-focused business, cards are your competitive context—what you're comparing costs against.</p>\n\n<div class=\"concept\"><b>Merchant Service Fee = Interchange + Scheme Fees + Acquirer Margin</b><br>\nWhen a merchant accepts a card, this is what they pay. Understanding each component helps you articulate PayTo's cost advantage.</div>\n\n<div class=\"concept\"><b>Interchange</b><br>\nFee paid to the card-issuing bank. RBA regulates via benchmarks:<br>\n• Credit: 0.5% weighted average<br>\n• Debit: 8 cents weighted average<br>\nVaries by card type (premium cards = higher) and merchant category.</div>\n\n<div class=\"concept\"><b>Scheme Fees</b><br>\nPaid to Visa/Mastercard/eftpos. Growing cost component, less transparent than interchange. RBA is examining these.</div>\n\n<div class=\"concept\"><b>Least-Cost Routing (LCR)</b><br>\nMost Australian debit cards are dual-network (eftpos + Visa/Mastercard). LCR lets merchants route via cheaper network. eftpos often cheaper. RBA supports LCR as pro-competition.</div>\n\n<div class=\"concept\"><b>FairPay Implication</b><br>\nIf a merchant pays 1.5% on cards and you offer PayTo at 0.3%, that's compelling. But understand what you're comparing to, and build flexibility for regulatory changes (RBA conclusions coming end-March 2026).</div>\n</section>\n\n<section class=\"section\">\n<h2>Payments Technology Stack</h2>\n<p>As CEO, you govern architecture. Here are the layers and typical build/partner decisions:</p>\n\n<div class=\"stack-layer\"><span class=\"name\">Frontend / UX</span><span class=\"decision\">Build (your differentiation)</span></div>\n<div class=\"stack-layer\"><span class=\"name\">Orchestration (routing, retries, webhooks)</span><span class=\"decision\">Build (core product logic)</span></div>\n<div class=\"stack-layer\"><span class=\"name\">Risk & Compliance (fraud, KYC)</span><span class=\"decision\">Buy tools + Build rules</span></div>\n<div class=\"stack-layer\"><span class=\"name\">Rail Connections (NPP, BECS, cards)</span><span class=\"decision\">Partner (sponsors/acquirers)</span></div>\n<div class=\"stack-layer\"><span class=\"name\">Ledger (balances, transactions)</span><span class=\"decision\">Build (source of truth)</span></div>\n<div class=\"stack-layer\"><span class=\"name\">Reconciliation</span><span class=\"decision\">Build (ops efficiency)</span></div>\n\n<div class=\"concept\"><b>Key Principle</b><br>\nOwn orchestration (your product logic), partner for rail access (you're not becoming an NPP participant), buy commodity tools (fraud screening, KYC), build differentiated UX (merchant dashboard, agreement flows).</div>\n</section>\n\n<section class=\"section\">\n<h2>Required Readings</h2>\n<a href=\"https://www.rba.gov.au/payments-and-infrastructure/debit-cards/least-cost-routing.html\" target=\"_blank\" class=\"resource\"><strong>1. Least-Cost Routing</strong><br><small>RBA — Definitions, rationale, expectations</small></a>\n<a href=\"https://www.rba.gov.au/payments-and-infrastructure/review-of-retail-payments-regulation/backgrounders/backgrounder-on-interchange-and-scheme-fees.html\" target=\"_blank\" class=\"resource\"><strong>2. Interchange & Scheme Fees</strong><br><small>RBA — Benchmarks and regulation</small></a>\n</section>\n\n<section class=\"section\">\n<h2>Knowledge Check</h2>\n<div class=\"card\"><div class=\"quiz\" id=\"quiz\">\n<div class=\"q\" data-correct=\"1\"><div class=\"q-text\">1. RBA's weighted average benchmark for credit interchange is:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q1\" value=\"0\">0.3%</label>\n<label><input type=\"radio\" name=\"q1\" value=\"1\">0.5%</label>\n<label><input type=\"radio\" name=\"q1\" value=\"2\">1.0%</label>\n</div></div>\n<div class=\"q\" data-correct=\"2\"><div class=\"q-text\">2. Least-Cost Routing allows merchants to:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q2\" value=\"0\">Bypass interchange entirely</label>\n<label><input type=\"radio\" name=\"q2\" value=\"1\">Accept only credit cards</label>\n<label><input type=\"radio\" name=\"q2\" value=\"2\">Route dual-network debit via cheaper network</label>\n</div></div>\n<div class=\"q\" data-correct=\"0\"><div class=\"q-text\">3. For FairPay, rail connections should typically be:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q3\" value=\"0\">Partnered (via sponsors)</label>\n<label><input type=\"radio\" name=\"q3\" value=\"1\">Built entirely in-house</label>\n<label><input type=\"radio\" name=\"q3\" value=\"2\">Outsourced to a white-label provider</label>\n</div></div>\n</div>\n<button class=\"btn\" onclick=\"checkQuiz()\">Check Answers</button>\n<div id=\"result\"></div></div>\n</section>\n\n<section class=\"section\">\n<div class=\"deliverable\"><h3>📋 Week 3 Deliverable</h3>\n<p>Build these for your capstone (Slides 5-7):</p>\n<ul class=\"checklist\">\n<li>☐ <strong>Card Economics Summary (½ slide):</strong> Key cost components for merchant card acceptance</li>\n<li>☐ <strong>Reference Architecture (1 slide):</strong> FairPay stack layers with build/partner decisions</li>\n<li>☐ <strong>Build vs Partner Table (½ slide):</strong> Each layer, your choice, brief rationale</li>\n</ul></div>\n</section>\n\n<div class=\"nav-footer\"><a href=\"week2.html\" class=\"nav-btn\">← Week 2</a><a href=\"week4.html\" class=\"nav-btn\">Week 4: Standards & Regulation →</a></div>\n</div>\n<script>\nfunction checkQuiz(){let s=0;document.querySelectorAll('.q').forEach(q=>{if(q.querySelector('input:checked')?.value===q.dataset.correct)s++});\nconst r=document.getElementById('result');r.style.display='block';r.style.background=s>=2?'rgba(34,197,94,.15)':'rgba(249,115,22,.15)';r.innerHTML='<strong>Score: '+s+'/3</strong>';}\n</script>\n</body>\n</html>\n\n\n--- WEEK 4 CONTENT ---\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Week 4: Standards & Regulatory Mapping | FairPay CEO Course</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--bg:#ffffff;--card:#f8fafc;--elevated:#f1f5f9;--teal:#14b8a6;--teal-dim:rgba(20,184,166,.15);--orange:#f97316;--text:#0f172a;--text2:#475569;--muted:#64748b;--border:#e2e8f0}\n*{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);line-height:1.7}\n.nav{position:sticky;top:0;background:rgba(255,255,255,.95);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;justify-content:space-between}.nav a{color:var(--text2);text-decoration:none}.nav a:hover{color:var(--teal)}\n.hero{padding:3rem 2rem;background:linear-gradient(180deg,rgba(20,184,166,.08),transparent);border-bottom:1px solid var(--border);text-align:center}\n.week-label{display:inline-block;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--teal);background:var(--teal-dim);padding:.5rem 1rem;border-radius:2rem;margin-bottom:1rem}\nh1{font-family:'Instrument Serif',serif;font-size:2.5rem;margin-bottom:1rem}.subtitle{color:var(--text2);max-width:700px;margin:0 auto}\n.container{max-width:900px;margin:0 auto;padding:2rem}.section{margin-bottom:3rem}\nh2{font-family:'Instrument Serif',serif;font-size:1.5rem;margin-bottom:1rem;color:var(--teal)}h3{font-size:1.1rem;margin:1.5rem 0 .75rem}p{margin-bottom:1rem;color:var(--text2)}\n.card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1rem}\n.concept{background:var(--elevated);border-left:3px solid var(--teal);padding:1rem;margin-bottom:1rem;border-radius:0 8px 8px 0}.concept b{color:var(--teal)}\n.timeline{background:var(--elevated);border:1px solid var(--orange);padding:.75rem 1rem;margin:.5rem 0;border-radius:8px;display:flex;gap:1rem;align-items:center}\n.timeline .date{color:var(--orange);font-weight:600;min-width:100px;font-size:.9rem}.timeline .event{color:var(--text2);font-size:.9rem}\n.resource{display:block;padding:1rem;background:var(--elevated);border:1px solid var(--border);border-radius:8px;margin-bottom:.5rem;text-decoration:none;color:var(--text)}.resource:hover{border-color:var(--teal)}.resource small{color:var(--muted)}\n.quiz{margin-top:1rem}.q{margin-bottom:1.5rem;padding-bottom:1.5rem;border-bottom:1px solid var(--border)}.q:last-child{border:none}.q-text{font-weight:500;margin-bottom:.75rem}\n.opts label{display:block;padding:.5rem .75rem;margin:.25rem 0;background:var(--elevated);border:1px solid var(--border);border-radius:6px;cursor:pointer}.opts label:hover{border-color:var(--teal)}.opts input{margin-right:.5rem}\n.btn{background:var(--teal);color:#fff;border:none;padding:.75rem 1.5rem;border-radius:8px;cursor:pointer;font-weight:600;margin-top:1rem}#result{margin-top:1rem;padding:1rem;border-radius:8px;display:none}\n.deliverable{background:linear-gradient(135deg,rgba(20,184,166,.1),rgba(20,184,166,.02));border:1px solid var(--teal);border-radius:12px;padding:1.5rem}\n.checklist{list-style:none;padding:0}.checklist li{padding:.5rem 0;border-bottom:1px solid var(--border);color:var(--text2)}.checklist li:last-child{border:none}\n.nav-footer{display:flex;justify-content:space-between;margin-top:3rem;padding-top:2rem;border-top:1px solid var(--border)}.nav-btn{padding:.75rem 1.5rem;background:var(--card);border:1px solid var(--border);border-radius:8px;text-decoration:none;color:var(--text2)}.nav-btn:hover{border-color:var(--teal);color:var(--text)}\n</style>\n</head>\n<body>\n<nav class=\"nav\"><a href=\"week3.html\">← Week 3</a><span style=\"color:var(--text);font-weight:600\">Week 4 of 6</span><a href=\"week5.html\">Week 5 →</a></nav>\n<header class=\"hero\"><span class=\"week-label\">Week 4</span><h1>Standards & Regulatory Mapping</h1><p class=\"subtitle\">Navigate ISO 20022, EMV, PCI DSS, and Australian regulatory requirements.</p></header>\n<div class=\"container\">\n\n<section class=\"section\">\n<h2>Learning Objectives</h2>\n<div class=\"card\"><ul style=\"color:var(--text2);padding-left:1.5rem\">\n<li>Understand key standards: ISO 20022, EMV tokenisation, PCI DSS</li>\n<li>Map Australian regulators and their relevance to FairPay</li>\n<li>Track Treasury licensing reforms and AUSTRAC obligations</li>\n<li>Build a regulatory perimeter and compliance roadmap</li>\n</ul></div>\n</section>\n\n<section class=\"section\">\n<h2>Technical Standards</h2>\n<div class=\"concept\"><b>ISO 20022</b><br>International standard for financial messaging. Rich, structured data with modelling methodology and central dictionary. NPP uses this—gives you reconciliation and reporting advantages over legacy formats.</div>\n<div class=\"concept\"><b>EMV Tokenisation</b><br>Replaces card PANs with constrained tokens. If tokens are compromised, fraud value is limited. Security layer for card storage. Relevant if you handle cards as fallback.</div>\n<div class=\"concept\"><b>EMV 3DS (3-D Secure)</b><br>Authentication for online card payments. Enables data exchange between merchant and issuer. Balances fraud prevention vs checkout friction.</div>\n<div class=\"concept\"><b>PCI DSS v4.0</b><br>Card security standard. Future-dated requirements became mandatory 31 March 2025. As CEO: define scope, assign responsibilities, ensure audit readiness. Minimize card data handling to reduce scope.</div>\n</section>\n\n<section class=\"section\">\n<h2>Australian Regulatory Landscape</h2>\n<div class=\"concept\"><b>RBA / Payments System Board</b><br>Sets policy direction. Operates FSS. Current focus: card costs, surcharging, resilience. Conclusions expected end-March 2026.</div>\n<div class=\"concept\"><b>ASIC — ePayments Code</b><br>Consumer protections for electronic payments. Currently voluntary subscription. Extended to cover NPP payments. Treasury may make mandatory via licensing reforms.</div>\n<div class=\"concept\"><b>AUSTRAC — AML/CTF</b><br>If you provide designated services, you must enrol and maintain an AML program BEFORE providing services. Reforms adding new designated services with staggered start dates.</div>\n<div class=\"concept\"><b>Treasury — Licensing Reforms</b><br>Payments System Modernisation Act commenced 19 Dec 2025. Tranche 1a consultation closed Nov 2025. Tranche 1b expected 2026. May capture FairPay depending on funds flow model.</div>\n</section>\n\n<section class=\"section\">\n<h2>Key Regulatory Dates</h2>\n<div class=\"timeline\"><span class=\"date\">19 Dec 2025</span><span class=\"event\">Payments System Modernisation Act commenced</span></div>\n<div class=\"timeline\"><span class=\"date\">31 Mar 2025</span><span class=\"event\">PCI DSS v4.0 future-dated requirements effective</span></div>\n<div class=\"timeline\"><span class=\"date\">End Mar 2026</span><span class=\"event\">RBA card costs/surcharging conclusions + timeline</span></div>\n<div class=\"timeline\"><span class=\"date\">31 Mar 2026</span><span class=\"event\">AUSTRAC reforms start (some new designated services)</span></div>\n<div class=\"timeline\"><span class=\"date\">1 Jul 2026</span><span class=\"event\">AUSTRAC reforms start (other new designated services)</span></div>\n<div class=\"timeline\"><span class=\"date\">2026</span><span class=\"event\">Treasury Tranche 1b consultation expected</span></div>\n</section>\n\n<section class=\"section\">\n<h2>Required Readings</h2>\n<a href=\"https://treasury.gov.au/policy-topics/banking-and-finance/payments-licensing-reforms\" target=\"_blank\" class=\"resource\"><strong>1. Payments Licensing Reforms</strong><br><small>Treasury — Tranches and timeline</small></a>\n<a href=\"https://www.asic.gov.au/epaymentscode\" target=\"_blank\" class=\"resource\"><strong>2. ePayments Code</strong><br><small>ASIC — Consumer protections</small></a>\n<a href=\"https://www.austrac.gov.au/business/new-to-austrac/your-obligations\" target=\"_blank\" class=\"resource\"><strong>3. Your Obligations</strong><br><small>AUSTRAC — AML/CTF requirements</small></a>\n<a href=\"https://www.iso20022.org/about-iso-20022\" target=\"_blank\" class=\"resource\"><strong>4. About ISO 20022</strong><br><small>ISO20022.org — Standard overview</small></a>\n</section>\n\n<section class=\"section\">\n<h2>Knowledge Check</h2>\n<div class=\"card\"><div class=\"quiz\" id=\"quiz\">\n<div class=\"q\" data-correct=\"0\"><div class=\"q-text\">1. Which messaging standard does NPP use?</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q1\" value=\"0\">ISO 20022</label>\n<label><input type=\"radio\" name=\"q1\" value=\"1\">SWIFT MT</label>\n<label><input type=\"radio\" name=\"q1\" value=\"2\">EDI</label>\n</div></div>\n<div class=\"q\" data-correct=\"1\"><div class=\"q-text\">2. When did the Payments System Modernisation Act commence?</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q2\" value=\"0\">1 January 2026</label>\n<label><input type=\"radio\" name=\"q2\" value=\"1\">19 December 2025</label>\n<label><input type=\"radio\" name=\"q2\" value=\"2\">1 July 2026</label>\n</div></div>\n<div class=\"q\" data-correct=\"2\"><div class=\"q-text\">3. AUSTRAC obligations require you to:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q3\" value=\"0\">Report annually after launch</label>\n<label><input type=\"radio\" name=\"q3\" value=\"1\">Register within 6 months of launch</label>\n<label><input type=\"radio\" name=\"q3\" value=\"2\">Enrol and have AML program BEFORE providing services</label>\n</div></div>\n</div>\n<button class=\"btn\" onclick=\"checkQuiz()\">Check Answers</button>\n<div id=\"result\"></div></div>\n</section>\n\n<section class=\"section\">\n<div class=\"deliverable\"><h3>📋 Week 4 Deliverable</h3>\n<p>Build these for your capstone (Slide 8 + memo):</p>\n<ul class=\"checklist\">\n<li>☐ <strong>Regulatory Perimeter Memo (2 pages):</strong> What FairPay does, whose money we touch, ASIC/AUSTRAC exposure, reform watchlist</li>\n<li>☐ <strong>Standards Checklist:</strong> ISO 20022 usage, PCI scope (if any), governance approach</li>\n<li>☐ <strong>Compliance Roadmap v1:</strong> What before launch, what builds over time</li>\n</ul></div>\n</section>\n\n<div class=\"nav-footer\"><a href=\"week3.html\" class=\"nav-btn\">← Week 3</a><a href=\"week5.html\" class=\"nav-btn\">Week 5: Fraud & Economics →</a></div>\n</div>\n<script>\nfunction checkQuiz(){let s=0;document.querySelectorAll('.q').forEach(q=>{if(q.querySelector('input:checked')?.value===q.dataset.correct)s++});\nconst r=document.getElementById('result');r.style.display='block';r.style.background=s>=2?'rgba(34,197,94,.15)':'rgba(249,115,22,.15)';r.innerHTML='<strong>Score: '+s+'/3</strong>';}\n</script>\n</body>\n</html>\n\n\n--- WEEK 5 CONTENT ---\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Week 5: Fraud, Economics & Integration | FairPay CEO Course</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--bg:#ffffff;--card:#f8fafc;--elevated:#f1f5f9;--teal:#14b8a6;--teal-dim:rgba(20,184,166,.15);--orange:#f97316;--text:#0f172a;--text2:#475569;--muted:#64748b;--border:#e2e8f0}\n*{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);line-height:1.7}\n.nav{position:sticky;top:0;background:rgba(255,255,255,.95);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;justify-content:space-between}.nav a{color:var(--text2);text-decoration:none}.nav a:hover{color:var(--teal)}\n.hero{padding:3rem 2rem;background:linear-gradient(180deg,rgba(20,184,166,.08),transparent);border-bottom:1px solid var(--border);text-align:center}\n.week-label{display:inline-block;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--teal);background:var(--teal-dim);padding:.5rem 1rem;border-radius:2rem;margin-bottom:1rem}\nh1{font-family:'Instrument Serif',serif;font-size:2.5rem;margin-bottom:1rem}.subtitle{color:var(--text2);max-width:700px;margin:0 auto}\n.container{max-width:900px;margin:0 auto;padding:2rem}.section{margin-bottom:3rem}\nh2{font-family:'Instrument Serif',serif;font-size:1.5rem;margin-bottom:1rem;color:var(--teal)}h3{font-size:1.1rem;margin:1.5rem 0 .75rem}p{margin-bottom:1rem;color:var(--text2)}\n.card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1rem}\n.concept{background:var(--elevated);border-left:3px solid var(--teal);padding:1rem;margin-bottom:1rem;border-radius:0 8px 8px 0}.concept b{color:var(--teal)}\n.stat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:1rem;margin:1rem 0}\n.stat{background:var(--elevated);border:1px solid var(--orange);padding:1.5rem;border-radius:12px;text-align:center}\n.stat-num{font-family:'Instrument Serif',serif;font-size:2rem;color:var(--orange)}.stat-label{font-size:.85rem;color:var(--text2)}\n.resource{display:block;padding:1rem;background:var(--elevated);border:1px solid var(--border);border-radius:8px;margin-bottom:.5rem;text-decoration:none;color:var(--text)}.resource:hover{border-color:var(--teal)}.resource small{color:var(--muted)}\n.quiz{margin-top:1rem}.q{margin-bottom:1.5rem;padding-bottom:1.5rem;border-bottom:1px solid var(--border)}.q:last-child{border:none}.q-text{font-weight:500;margin-bottom:.75rem}\n.opts label{display:block;padding:.5rem .75rem;margin:.25rem 0;background:var(--elevated);border:1px solid var(--border);border-radius:6px;cursor:pointer}.opts label:hover{border-color:var(--teal)}.opts input{margin-right:.5rem}\n.btn{background:var(--teal);color:#fff;border:none;padding:.75rem 1.5rem;border-radius:8px;cursor:pointer;font-weight:600;margin-top:1rem}#result{margin-top:1rem;padding:1rem;border-radius:8px;display:none}\n.deliverable{background:linear-gradient(135deg,rgba(20,184,166,.1),rgba(20,184,166,.02));border:1px solid var(--teal);border-radius:12px;padding:1.5rem}\n.checklist{list-style:none;padding:0}.checklist li{padding:.5rem 0;border-bottom:1px solid var(--border);color:var(--text2)}.checklist li:last-child{border:none}\n.nav-footer{display:flex;justify-content:space-between;margin-top:3rem;padding-top:2rem;border-top:1px solid var(--border)}.nav-btn{padding:.75rem 1.5rem;background:var(--card);border:1px solid var(--border);border-radius:8px;text-decoration:none;color:var(--text2)}.nav-btn:hover{border-color:var(--teal);color:var(--text)}\n</style>\n</head>\n<body>\n<nav class=\"nav\"><a href=\"week4.html\">← Week 4</a><span style=\"color:var(--text);font-weight:600\">Week 5 of 6</span><a href=\"week6.html\">Week 6 →</a></nav>\n<header class=\"hero\"><span class=\"week-label\">Week 5</span><h1>Fraud, Economics & Integration</h1><p class=\"subtitle\">Build FairPay's risk register, unit economics, and reconciliation workflows.</p></header>\n<div class=\"container\">\n\n<section class=\"section\">\n<h2>Learning Objectives</h2>\n<div class=\"card\"><ul style=\"color:var(--text2);padding-left:1.5rem\">\n<li>Understand Australian fraud landscape and PayTo's different risk profile</li>\n<li>Build a CEO-level risk register</li>\n<li>Construct unit economics and pricing model</li>\n<li>Design reconciliation and onboarding workflows</li>\n</ul></div>\n</section>\n\n<section class=\"section\">\n<h2>Australian Fraud Landscape</h2>\n<div class=\"stat-grid\">\n<div class=\"stat\"><div class=\"stat-num\">$913M</div><div class=\"stat-label\">Total card fraud (2024)</div></div>\n<div class=\"stat\"><div class=\"stat-num\">$816M</div><div class=\"stat-label\">CNP fraud (2024)</div></div>\n<div class=\"stat\"><div class=\"stat-num\">89%</div><div class=\"stat-label\">CNP share of card fraud</div></div>\n</div>\n<div class=\"concept\"><b>Why CNP Dominates</b><br>Card-not-present fraud is high because cards are used online without physical verification. Stolen card details can be used remotely.</div>\n<div class=\"concept\"><b>PayTo's Different Profile</b><br>Customer authorizes agreements in their banking app with their bank's security. No stored credentials at merchant. Different risk model—but new risks emerge: agreement abuse, social engineering, merchant fraud.</div>\n</section>\n\n<section class=\"section\">\n<h2>Building Your Risk Register</h2>\n<p>Categories to include:</p>\n<div class=\"concept\"><b>Fraud/Scams</b> — Unauthorized collections, merchant fraud, social engineering of customers</div>\n<div class=\"concept\"><b>Compliance</b> — AUSTRAC failures, ePayments Code breaches, licensing gaps</div>\n<div class=\"concept\"><b>Cyber</b> — Data breach, API security, credential compromise</div>\n<div class=\"concept\"><b>Operational</b> — System outages, reconciliation failures, support overload</div>\n<div class=\"concept\"><b>Liquidity/Safeguarding</b> — If holding funds: safeguarding requirements, settlement timing</div>\n<div class=\"concept\"><b>Reputational</b> — Merchant failures reflecting on FairPay, public incidents</div>\n<p style=\"margin-top:1rem\">For each risk: scenario, existing controls, KRIs (key risk indicators), owner, residual rating.</p>\n</section>\n\n<section class=\"section\">\n<h2>Unit Economics</h2>\n<div class=\"concept\"><b>Cost Stack</b><br>\nTransaction costs (PayTo fees from sponsor) + Risk costs (fraud losses, disputes) + Operations (support, reconciliation) + Compliance (AML program, reporting) + Infrastructure (systems, monitoring) = Total cost per transaction</div>\n<div class=\"concept\"><b>Pricing</b><br>Price above cost stack with margin. Consider: blended (simple) vs cost-plus (transparent). Test sensitivity to regulatory changes—if RBA shifts card costs, does your comparative value prop hold?</div>\n</section>\n\n<section class=\"section\">\n<h2>Reconciliation & Integration</h2>\n<div class=\"concept\"><b>Daily Reconciliation</b><br>Expected settlements vs actual. Handle exceptions: missing, duplicates, timing differences. ISO 20022's rich data makes matching easier—use it.</div>\n<div class=\"concept\"><b>Onboarding Flow</b><br>Merchant KYB → Agreement setup → Test transactions → Go live. Design for self-service where possible.</div>\n<div class=\"concept\"><b>Support Surface</b><br>What questions will merchants ask? Failed collections, disputed agreements, settlement queries. Design support tooling before you need it.</div>\n</section>\n\n<section class=\"section\">\n<h2>Required Readings</h2>\n<a href=\"https://auspaynet.com.au/resources/fraud-statistics/2024-Calendar-year\" target=\"_blank\" class=\"resource\"><strong>1. Fraud Statistics 2024</strong><br><small>AusPayNet — Australian fraud data</small></a>\n<a href=\"https://handbook.apra.gov.au/standard/cps-234\" target=\"_blank\" class=\"resource\"><strong>2. CPS 234 Information Security</strong><br><small>APRA — Partner security expectations</small></a>\n</section>\n\n<section class=\"section\">\n<h2>Knowledge Check</h2>\n<div class=\"card\"><div class=\"quiz\" id=\"quiz\">\n<div class=\"q\" data-correct=\"1\"><div class=\"q-text\">1. CNP fraud in Australia (2024) was approximately:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q1\" value=\"0\">$200 million</label>\n<label><input type=\"radio\" name=\"q1\" value=\"1\">$816 million</label>\n<label><input type=\"radio\" name=\"q1\" value=\"2\">$2 billion</label>\n</div></div>\n<div class=\"q\" data-correct=\"0\"><div class=\"q-text\">2. PayTo changes fraud risk because:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q2\" value=\"0\">Customer authorizes in their bank app with bank security</label>\n<label><input type=\"radio\" name=\"q2\" value=\"1\">There are no fraud risks with PayTo</label>\n<label><input type=\"radio\" name=\"q2\" value=\"2\">Merchants store customer credentials</label>\n</div></div>\n<div class=\"q\" data-correct=\"2\"><div class=\"q-text\">3. Unit economics should include sensitivity analysis for:</div><div class=\"opts\">\n<label><input type=\"radio\" name=\"q3\" value=\"0\">Weather patterns</label>\n<label><input type=\"radio\" name=\"q3\" value=\"1\">Competitor marketing spend</label>\n<label><input type=\"radio\" name=\"q3\" value=\"2\">Regulatory changes affecting card costs</label>\n</div></div>\n</div>\n<button class=\"btn\" onclick=\"checkQuiz()\">Check Answers</button>\n<div id=\"result\"></div></div>\n</section>\n\n<section class=\"section\">\n<div class=\"deliverable\"><h3>📋 Week 5 Deliverable</h3>\n<p>Build these for your capstone (Slides 9-11):</p>\n<ul class=\"checklist\">\n<li>☐ <strong>Risk Register v1 (1 slide + appendix):</strong> Top 10 risks across categories with controls and KRIs</li>\n<li>☐ <strong>Unit Economics Model (1 slide):</strong> Cost stack, pricing logic, 3 sensitivity scenarios</li>\n<li>☐ <strong>Reconciliation Checklist:</strong> MVP process, exception handling, scale-up roadmap</li>\n</ul></div>\n</section>\n\n<div class=\"nav-footer\"><a href=\"week4.html\" class=\"nav-btn\">← Week 4</a><a href=\"week6.html\" class=\"nav-btn\">Week 6: Partnerships & Capstone →</a></div>\n</div>\n<script>\nfunction checkQuiz(){let s=0;document.querySelectorAll('.q').forEach(q=>{if(q.querySelector('input:checked')?.value===q.dataset.correct)s++});\nconst r=document.getElementById('result');r.style.display='block';r.style.background=s>=2?'rgba(34,197,94,.15)':'rgba(249,115,22,.15)';r.innerHTML='<strong>Score: '+s+'/3</strong>';}\n</script>\n</body>\n</html>\n\n\n--- WEEK 6 CONTENT ---\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Week 6: Partnerships, Trends & Capstone | FairPay CEO Course</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--bg:#ffffff;--card:#f8fafc;--elevated:#f1f5f9;--teal:#14b8a6;--teal-dim:rgba(20,184,166,.15);--orange:#f97316;--text:#0f172a;--text2:#475569;--muted:#64748b;--border:#e2e8f0}\n*{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);line-height:1.7}\n.nav{position:sticky;top:0;background:rgba(255,255,255,.95);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;justify-content:space-between}.nav a{color:var(--text2);text-decoration:none}.nav a:hover{color:var(--teal)}\n.hero{padding:3rem 2rem;background:linear-gradient(180deg,rgba(20,184,166,.08),transparent);border-bottom:1px solid var(--border);text-align:center}\n.week-label{display:inline-block;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--teal);background:var(--teal-dim);padding:.5rem 1rem;border-radius:2rem;margin-bottom:1rem}\nh1{font-family:'Instrument Serif',serif;font-size:2.5rem;margin-bottom:1rem}.subtitle{color:var(--text2);max-width:700px;margin:0 auto}\n.container{max-width:900px;margin:0 auto;padding:2rem}.section{margin-bottom:3rem}\nh2{font-family:'Instrument Serif',serif;font-size:1.5rem;margin-bottom:1rem;color:var(--teal)}h3{font-size:1.1rem;margin:1.5rem 0 .75rem}p{margin-bottom:1rem;color:var(--text2)}\n.card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.5rem;margin-bottom:1rem}\n.concept{background:var(--elevated);border-left:3px solid var(--teal);padding:1rem;margin-bottom:1rem;border-radius:0 8px 8px 0}.concept b{color:var(--teal)}\n.timeline{background:var(--elevated);border:1px solid var(--orange);padding:.75rem 1rem;margin:.5rem 0;border-radius:8px;display:flex;gap:1rem;align-items:center}\n.timeline .date{color:var(--orange);font-weight:600;min-width:100px;font-size:.9rem}.timeline .event{color:var(--text2);font-size:.9rem}\n.capstone{background:linear-gradient(135deg,rgba(20,184,166,.2),rgba(20,184,166,.05));border:2px solid var(--teal);border-radius:16px;padding:2rem;margin:2rem 0}\n.capstone h3{font-family:'Instrument Serif',serif;font-size:1.5rem;color:var(--teal);margin-top:0}\n.rubric{display:grid;grid-template-columns:1fr auto;gap:.5rem;padding:.75rem 0;border-bottom:1px solid var(--border)}\n.rubric:last-child{border:none}\n.rubric-name{color:var(--text)}.rubric-weight{color:var(--orange);font-weight:600}\n.checklist{list-style:none;padding:0}.checklist li{padding:.5rem 0;border-bottom:1px solid var(--border);color:var(--text2)}.checklist li:last-child{border:none}\n.nav-footer{display:flex;justify-content:space-between;margin-top:3rem;padding-top:2rem;border-top:1px solid var(--border)}.nav-btn{padding:.75rem 1.5rem;background:var(--card);border:1px solid var(--border);border-radius:8px;text-decoration:none;color:var(--text2)}.nav-btn:hover{border-color:var(--teal);color:var(--text)}\n</style>\n</head>\n<body>\n<nav class=\"nav\"><a href=\"week5.html\">← Week 5</a><span style=\"color:var(--text);font-weight:600\">Week 6 of 6</span><a href=\"../index.html\">Course Home →</a></nav>\n<header class=\"hero\"><span class=\"week-label\">Week 6</span><h1>Partnerships, Trends & Capstone</h1><p class=\"subtitle\">Finalize partner strategy and complete your FairPay Payments Strategy Pack.</p></header>\n<div class=\"container\">\n\n<section class=\"section\">\n<h2>Learning Objectives</h2>\n<div class=\"card\"><ul style=\"color:var(--text2);padding-left:1.5rem\">\n<li>Identify and evaluate key partner categories</li>\n<li>Understand negotiation priorities for each partner type</li>\n<li>Track external changes affecting FairPay strategy</li>\n<li>Complete and present your capstone Strategy Pack</li>\n</ul></div>\n</section>\n\n<section class=\"section\">\n<h2>Partner Categories</h2>\n<div class=\"concept\"><b>NPP Access Partner</b> (Critical)<br>Provides PayTo capability. Negotiate: pricing (per-transaction, minimums), SLAs (uptime, latency), API quality, support responsiveness, roadmap alignment.</div>\n<div class=\"concept\"><b>BECS Sponsor</b><br>For backward compatibility. Simpler relationship. Focus: pricing, file handling, settlement timing.</div>\n<div class=\"concept\"><b>KYC/KYB Provider</b><br>Merchant identity verification. Consider: coverage (ABN, director checks), speed, API integration, cost per check.</div>\n<div class=\"concept\"><b>Fraud/Risk Tools</b><br>Transaction monitoring, risk scoring. Evaluate: false positive rates, integration effort, pricing model.</div>\n<div class=\"concept\"><b>Compliance Advisory</b><br>AUSTRAC program setup, regulatory navigation. Especially valuable at pre-revenue stage.</div>\n</section>\n\n<section class=\"section\">\n<h2>Negotiation Priorities</h2>\n<div class=\"card\">\n<p><b>Commercial:</b> Pricing structure, minimum commitments, pass-through costs, volume discounts</p>\n<p><b>Risk:</b> Fraud liability allocation, dispute handling, indemnities</p>\n<p><b>Data:</b> Settlement reports, reconciliation fields, API access to transaction data</p>\n<p><b>Security:</b> PCI scope implications, incident response, CPS 234 alignment (for APRA-regulated partners)</p>\n</div>\n</section>\n\n<section class=\"section\">\n<h2>External Change Watchlist</h2>\n<p>Key dates affecting FairPay's strategic assumptions:</p>\n<div class=\"timeline\"><span class=\"date\">End Mar 2026</span><span class=\"event\">RBA card costs/surcharging Conclusions Paper + timeline</span></div>\n<div class=\"timeline\"><span class=\"date\">31 Mar 2026</span><span class=\"event\">AUSTRAC reforms start (some new designated services)</span></div>\n<div class=\"timeline\"><span class=\"date\">1 Jul 2026</span><span class=\"event\">AUSTRAC reforms start (other new designated services)</span></div>\n<div class=\"timeline\"><span class=\"date\">2026</span><span class=\"event\">Treasury Tranche 1b consultation + Tranche 2 considerations</span></div>\n<div class=\"timeline\"><span class=\"date\">Ongoing</span><span class=\"event\">PayTo bank coverage expansion, customer adoption</span></div>\n</section>\n\n<section class=\"section\">\n<div class=\"capstone\">\n<h3>🎓 Capstone: FairPay Payments Strategy Pack</h3>\n<p><b>Deliverables:</b></p>\n<ul style=\"color:var(--text2);padding-left:1.5rem;margin-bottom:1.5rem\">\n<li>Slide deck (10-15 slides): Board/investor-ready</li>\n<li>Executive memo (2 pages): Written narrative with assumptions</li>\n</ul>\n\n<p><b>Required Contents:</b></p>\n<ul class=\"checklist\">\n<li>☐ FairPay positioning: who we serve, which problems, why now</li>\n<li>☐ Rail strategy: which rails for which use cases (with decision matrix)</li>\n<li>☐ Reference architecture: own vs partner boundaries</li>\n<li>☐ Unit economics: cost stack, pricing, sensitivities</li>\n<li>☐ Risk & compliance: regulatory perimeter, risk register highlights</li>\n<li>☐ Partner strategy: who we need, what we negotiate</li>\n<li>☐ Roadmap: next 12-24 months with external milestones</li>\n</ul>\n\n<h3 style=\"margin-top:2rem\">Assessment Rubric</h3>\n<div class=\"rubric\"><span class=\"rubric-name\">Strategic coherence (clear choices, logical sequencing)</span><span class=\"rubric-weight\">20%</span></div>\n<div class=\"rubric\"><span class=\"rubric-name\">Rail strategy realism (defensible, constraints acknowledged)</span><span class=\"rubric-weight\">15%</span></div>\n<div class=\"rubric\"><span class=\"rubric-name\">Architecture & operability (supports reconciliation, disputes)</span><span class=\"rubric-weight\">15%</span></div>\n<div class=\"rubric\"><span class=\"rubric-name\">Economics & pricing (transparent assumptions, stress-tested)</span><span class=\"rubric-weight\">20%</span></div>\n<div class=\"rubric\"><span class=\"rubric-name\">Risk & compliance (perimeter scoped, obligations addressed)</span><span class=\"rubric-weight\">20%</span></div>\n<div class=\"rubric\"><span class=\"rubric-name\">Communication quality (clear narrative, explicit unknowns)</span><span class=\"rubric-weight\">10%</span></div>\n</div>\n</section>\n\n<section class=\"section\">\n<h2>CEO Decision Log</h2>\n<p>Complete this as your final action item:</p>\n<div class=\"card\">\n<p><b>Top 5 Decisions Made:</b> What have you decided through this course?</p>\n<p><b>Next 3 Meetings:</b> Who do you need to talk to? (potential sponsors, advisors, customers)</p>\n<p><b>Next 2 Experiments:</b> What will you test to validate assumptions?</p>\n</div>\n</section>\n\n<div class=\"nav-footer\"><a href=\"week5.html\" class=\"nav-btn\">← Week 5</a><a href=\"../index.html\" class=\"nav-btn\">🎓 Complete Course →</a></div>\n</div>\n</body>\n</html>\n" };
